  INSERT INTO lessons (course_id, slug, translations, order_index, estimated_minutes, xp_reward, format, is_published)
  INSERT INTO lesson_turns (lesson_id, order_index, turn_type, content, xp_reward, is_required) VALUES
    (v_lesson, 1, 'tutor_message', $lj${"text":"Try this: name one thing you did today that didn't depend on another living thing.\n\nThe air you breathed? Plants made it. The water you drank? A whole web of organisms cleaned it. Your breakfast? Soil, microbes, and sunlight, working together.\n\nWe never notice. Today, we notice.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 2, 'tutor_message', $lj${"text":"We share this planet with *millions* of other living beings — from **micro-organisms** and **bacteria**, to **lichens**, to **banyan trees**, **elephants**, and **blue whales**.\n\nAll of it together makes up the planet's immense **biodiversity** — its sheer variety of life.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 3, 'tutor_message', $lj${"text":"Now the humbling part.\n\nWe humans, along with *every* other living thing, form a single **web** — a complex *ecological system*. We are not perched above it, looking down.\n\nWe are **one strand** in it. And like any strand, we depend on the whole web to survive.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 4, 'media', $lj${"kind":"image","url":"https://dfdocnhhxrnvblbwwium.supabase.co/storage/v1/object/public/lesson-images/b-class-10-geography-ch02-forest-and-wildlife-resources/c1l1-biodiverse-forest.png","caption":"A lush, biodiverse Indian forest — countless species sharing one living web.","aspect_ratio":1.7778}$lj$::jsonb, 0, true),
    (v_lesson, 5, 'svg_graphic', $lj${"title":"THE WEB OF LIFE","caption":"Sun, forests, microbes, animals, humans — all knotted together. You are one node, not the top.","svg":"<svg viewBox=\"0 0 360 200\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <line x1=\"180\" y1=\"30\" x2=\"70\" y2=\"92\" stroke=\"#cbd5e1\" stroke-width=\"1.5\"/>\n  <line x1=\"180\" y1=\"30\" x2=\"290\" y2=\"92\" stroke=\"#cbd5e1\" stroke-width=\"1.5\"/>\n  <line x1=\"70\" y1=\"96\" x2=\"290\" y2=\"96\" stroke=\"#cbd5e1\" stroke-width=\"1.5\"/>\n  <line x1=\"70\" y1=\"96\" x2=\"120\" y2=\"166\" stroke=\"#cbd5e1\" stroke-width=\"1.5\"/>\n  <line x1=\"70\" y1=\"96\" x2=\"250\" y2=\"166\" stroke=\"#cbd5e1\" stroke-width=\"1.5\"/>\n  <line x1=\"290\" y1=\"96\" x2=\"120\" y2=\"166\" stroke=\"#cbd5e1\" stroke-width=\"1.5\"/>\n  <line x1=\"290\" y1=\"96\" x2=\"250\" y2=\"166\" stroke=\"#cbd5e1\" stroke-width=\"1.5\"/>\n  <line x1=\"120\" y1=\"166\" x2=\"250\" y2=\"166\" stroke=\"#cbd5e1\" stroke-width=\"1.5\"/>\n  <circle cx=\"180\" cy=\"28\" r=\"17\" fill=\"#fde68a\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"180\" y=\"32\" text-anchor=\"middle\" font-size=\"8\" fill=\"#92400e\">sun</text>\n  <circle cx=\"70\" cy=\"96\" r=\"24\" fill=\"#bbf7d0\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"70\" y=\"93\" text-anchor=\"middle\" font-size=\"8\" fill=\"#166534\">forests,</text>\n  <text x=\"70\" y=\"103\" text-anchor=\"middle\" font-size=\"8\" fill=\"#166534\">plants</text>\n  <circle cx=\"290\" cy=\"96\" r=\"24\" fill=\"#99f6e4\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"290\" y=\"93\" text-anchor=\"middle\" font-size=\"8\" fill=\"#115e59\">microbes,</text>\n  <text x=\"290\" y=\"103\" text-anchor=\"middle\" font-size=\"8\" fill=\"#115e59\">bacteria</text>\n  <circle cx=\"120\" cy=\"168\" r=\"22\" fill=\"#fed7aa\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"120\" y=\"171\" text-anchor=\"middle\" font-size=\"8\" fill=\"#9a3412\">animals</text>\n  <circle cx=\"250\" cy=\"168\" r=\"22\" fill=\"#bfdbfe\" stroke=\"#0f172a\" stroke-width=\"2.5\"/>\n  <text x=\"250\" y=\"165\" text-anchor=\"middle\" font-size=\"8\" font-weight=\"bold\" fill=\"#1e3a8a\">humans</text>\n  <text x=\"250\" y=\"176\" text-anchor=\"middle\" font-size=\"7\" fill=\"#1e3a8a\">(you)</text>\n</svg>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 6, 'tutor_message', $lj${"text":"How *literally* do we depend on the web? Completely.\n\nPlants, animals, and micro-organisms **re-create** the very things we can't live without:\n\n- the **air** we breathe\n- the **water** we drink\n- the **soil** that grows our food\n\nRemove them, and we don't last long.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 7, 'tutor_message', $lj${"text":"And at the *base* of the whole web sit the **forests**.\n\nThey are the **primary producers** — the living things that turn sunlight into food. Everything else eats that food, directly or indirectly. The forest quietly feeds the entire web.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 8, 'tutor_message', $lj${"text":"So what is **biodiversity**, exactly?\n\nIt's the immense richness of wildlife and cultivated species — *diverse in form and function, but closely integrated through a network of interdependencies.*\n\nHold onto that last word: **interdependencies**. In a web, nothing stands alone.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 9, 'html_animation', $lj${"title":"PULL ONE STRAND","caption":"Tug a single strand of the web and the whole thing trembles — all the way up to us.","html":"<div style=\"background:#f8fafc;padding:18px 12px;border-radius:12px;text-align:center;\">\n  <style>\n    @keyframes geoShake { 0%,100%{transform:translate(0,0)} 25%{transform:translate(-3px,2px)} 50%{transform:translate(3px,-2px)} 75%{transform:translate(-2px,-2px)} }\n    @keyframes geoPulse { 0%,100%{fill:#fca5a5} 50%{fill:#dc2626} }\n    .geo-web { animation: geoShake 1.6s ease-in-out infinite; transform-origin:center; }\n    .geo-pulled { animation: geoPulse 1.6s ease-in-out infinite; }\n  </style>\n  <svg viewBox=\"0 0 300 150\" style=\"max-width:320px;width:100%\" font-family=\"sans-serif\">\n    <g class=\"geo-web\">\n      <line x1=\"150\" y1=\"30\" x2=\"60\" y2=\"90\" stroke=\"#94a3b8\" stroke-width=\"1.5\"/>\n      <line x1=\"150\" y1=\"30\" x2=\"240\" y2=\"90\" stroke=\"#94a3b8\" stroke-width=\"1.5\"/>\n      <line x1=\"60\" y1=\"90\" x2=\"240\" y2=\"90\" stroke=\"#94a3b8\" stroke-width=\"1.5\"/>\n      <line x1=\"60\" y1=\"90\" x2=\"150\" y2=\"125\" stroke=\"#94a3b8\" stroke-width=\"1.5\"/>\n      <line x1=\"240\" y1=\"90\" x2=\"150\" y2=\"125\" stroke=\"#94a3b8\" stroke-width=\"1.5\"/>\n      <circle cx=\"150\" cy=\"30\" r=\"10\" fill=\"#86efac\" stroke=\"#0f172a\" stroke-width=\"1\"/>\n      <circle cx=\"60\" cy=\"90\" r=\"10\" fill=\"#93c5fd\" stroke=\"#0f172a\" stroke-width=\"1\"/>\n      <circle cx=\"240\" cy=\"90\" r=\"10\" fill=\"#fdba74\" stroke=\"#0f172a\" stroke-width=\"1\"/>\n      <circle cx=\"150\" cy=\"125\" r=\"11\" class=\"geo-pulled\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n    </g>\n    <text x=\"150\" y=\"147\" text-anchor=\"middle\" font-size=\"8\" fill=\"#991b1b\">one strand pulled — the whole web shakes</text>\n  </svg>\n</div>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 10, 'tutor_message', $lj${"text":"*What would break if one strand snapped?*\n\nPull out the bees, or the soil bacteria, or a single forest, and the tremor runs *through* the web — up the strands, all the way to us.\n\nThat's why no extinction is ever really \"small\". The web feels every loss.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 11, 'mcq', $lj${"question":"Why does the chapter call forests the 'primary producers' of the ecological system?","options":[{"id":"a","text":"Because they produce the most timber for human use.","is_correct":false,"rationale":"Timber is a human *use* of forests, not why they're called primary producers in ecology."},{"id":"b","text":"Because they turn sunlight into food that every other living thing depends on, directly or indirectly.","is_correct":true,"rationale":"Exactly. Primary producers make the food at the base of the web — everything else feeds on it down the line."},{"id":"c","text":"Because humans planted most of them first.","is_correct":false,"rationale":"Forests are not primarily human-made, and that's unrelated to the meaning of 'primary producer'."},{"id":"d","text":"Because they are the oldest living things on Earth.","is_correct":false,"rationale":"Age isn't the point. 'Primary producer' is about making food from sunlight at the base of the food web."}],"xp":10}$lj$::jsonb, 10, true),
    (v_lesson, 12, 'tap_to_match', $lj${"prompt":"Match each part of the web to its role.","left":[{"id":"l1","label":"Forests and plants"},{"id":"l2","label":"Micro-organisms and bacteria"},{"id":"l3","label":"The whole web together"},{"id":"l4","label":"Humans"}],"right":[{"id":"r1","label":"Primary producers — turn sunlight into food"},{"id":"r2","label":"Help re-create clean soil, air, and water"},{"id":"r3","label":"Biodiversity — variety held by interdependencies"},{"id":"r4","label":"One dependent strand, not the top"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]}$lj$::jsonb, 10, true),
    (v_lesson, 13, 'exercise', $lj${"instruction":"Pick three things you used in the last hour — food, water, paper, a wooden object, the air in your room.\n\nOn paper, trace each one back to a *living* part of the web that made it possible. Then type one of them and its living source below.\n","tool":"pencil","placeholder":"The ___ I used came from ___ in the web."}$lj$::jsonb, 15, true),
    (v_lesson, 14, 'fill_in_the_blank', $lj${"prompt":"Lock in the two key ideas.","template":"Forests are the {{blank-1}} producers of the ecological system, and biodiversity is held together by a network of {{blank-2}}.\n","answers":[{"id":"blank-1","accepted":["primary","Primary"]},{"id":"blank-2","accepted":["interdependencies","interdependence","Interdependencies"]}]}$lj$::jsonb, 10, true),
    (v_lesson, 15, 'reflection', $lj${"prompt":"\"We are one strand in the web, not the top.\" Does that change how you picture your place in nature — or does it feel uncomfortable? Be honest.\n\nNo right answer.\n","placeholder":"Thinking of myself as one strand..."}$lj$::jsonb, 5, true),
    (v_lesson, 16, 'checkpoint', $lj${"title":"You see yourself inside the web of life, not above it.","summary":"The planet runs on biodiversity — a web of millions of species, tied together by interdependencies, with forests as the primary producers feeding it all. We're one strand, utterly dependent on the rest.\n\nAnd here's the thing: India holds one of the *richest* sections of that web on Earth. Just how much living wealth does this one country carry — and why is it under threat? That's the next lesson.\n","xp":0}$lj$::jsonb, 0, true);
  INSERT INTO lessons (course_id, slug, translations, order_index, estimated_minutes, xp_reward, format, is_published)
  INSERT INTO lesson_turns (lesson_id, order_index, turn_type, content, xp_reward, is_required) VALUES
    (v_lesson, 1, 'tutor_message', $lj${"text":"Imagine India's wildlife as a vast **library**.\n\nNow imagine we've only *read about a third* of the books. The rest are still on the shelves — uncatalogued, some never even opened.\n\nThat's not a metaphor stretch. It's roughly the truth.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 2, 'tutor_message', $lj${"text":"India is one of the **richest countries on Earth** for biological diversity — a vast array of **flora** (plant life) and **fauna** (animal life).\n\nFrom the Himalayas to the coasts to the deserts, few places on the planet pack in this much variety of life.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 3, 'tutor_message', $lj${"text":"Here's the astonishing part.\n\nThe species we've actually *named and studied* may be only a fraction of what's really here. Scientists think the true number could be **two or three times** higher — still waiting to be discovered.\n\nMost of India's living library, quite literally, is *unread*.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 4, 'media', $lj${"kind":"image","url":"https://dfdocnhhxrnvblbwwium.supabase.co/storage/v1/object/public/lesson-images/b-class-10-geography-ch02-forest-and-wildlife-resources/c1l2-india-wildlife.png","caption":"India's living wealth: tiger, elephant, peacock, deer, hornbill — a fraction of its biodiversity.","aspect_ratio":1.7778}$lj$::jsonb, 0, true),
    (v_lesson, 5, 'svg_graphic', $lj${"title":"INDIA'S LIBRARY OF LIFE","caption":"The species we know (left) may be just a third — the rest are still undiscovered.","svg":"<svg viewBox=\"0 0 360 160\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <rect x=\"14\" y=\"20\" width=\"332\" height=\"104\" rx=\"4\" fill=\"#f8fafc\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <rect x=\"26\" y=\"32\" width=\"14\" height=\"80\" fill=\"#16a34a\"/>\n  <rect x=\"44\" y=\"32\" width=\"14\" height=\"80\" fill=\"#0891b2\"/>\n  <rect x=\"62\" y=\"32\" width=\"14\" height=\"80\" fill=\"#ca8a04\"/>\n  <rect x=\"80\" y=\"32\" width=\"14\" height=\"80\" fill=\"#9333ea\"/>\n  <rect x=\"98\" y=\"32\" width=\"14\" height=\"80\" fill=\"#dc2626\"/>\n  <line x1=\"120\" y1=\"24\" x2=\"120\" y2=\"120\" stroke=\"#94a3b8\" stroke-width=\"1.5\" stroke-dasharray=\"4 3\"/>\n  <rect x=\"132\" y=\"40\" width=\"12\" height=\"72\" fill=\"#e2e8f0\" stroke=\"#cbd5e1\"/>\n  <rect x=\"150\" y=\"40\" width=\"12\" height=\"72\" fill=\"#e2e8f0\" stroke=\"#cbd5e1\"/>\n  <rect x=\"168\" y=\"40\" width=\"12\" height=\"72\" fill=\"#e2e8f0\" stroke=\"#cbd5e1\"/>\n  <rect x=\"186\" y=\"40\" width=\"12\" height=\"72\" fill=\"#e2e8f0\" stroke=\"#cbd5e1\"/>\n  <rect x=\"204\" y=\"40\" width=\"12\" height=\"72\" fill=\"#e2e8f0\" stroke=\"#cbd5e1\"/>\n  <rect x=\"222\" y=\"40\" width=\"12\" height=\"72\" fill=\"#e2e8f0\" stroke=\"#cbd5e1\"/>\n  <rect x=\"240\" y=\"40\" width=\"12\" height=\"72\" fill=\"#e2e8f0\" stroke=\"#cbd5e1\"/>\n  <rect x=\"258\" y=\"40\" width=\"12\" height=\"72\" fill=\"#e2e8f0\" stroke=\"#cbd5e1\"/>\n  <rect x=\"276\" y=\"40\" width=\"12\" height=\"72\" fill=\"#e2e8f0\" stroke=\"#cbd5e1\"/>\n  <rect x=\"294\" y=\"40\" width=\"12\" height=\"72\" fill=\"#e2e8f0\" stroke=\"#cbd5e1\"/>\n  <text x=\"300\" y=\"80\" text-anchor=\"middle\" font-size=\"22\" fill=\"#94a3b8\">?</text>\n  <text x=\"68\" y=\"140\" text-anchor=\"middle\" font-size=\"8\" fill=\"#166534\">known species (~1/3)</text>\n  <text x=\"225\" y=\"140\" text-anchor=\"middle\" font-size=\"8\" fill=\"#64748b\">still to be discovered (~2/3)</text>\n</svg>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 6, 'tutor_message', $lj${"text":"And this wealth isn't off in some distant jungle. It's woven into **daily life** all around you — the food on your plate, the medicines you take, the wood in your home, the festivals, the songs.\n\nWe're so surrounded by it that we *take it for granted* — like air.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 7, 'tutor_message', $lj${"text":"Across India, folk songs and stories celebrate a *harmonious* bond between people and nature.\n\nA Lepcha folk song gathers its music *\"from the springs, the rivers, the mountains, the forests, the insects and the animals.\"* Nature isn't scenery in these traditions — it's family.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 8, 'tutor_message', $lj${"text":"But lately, this living wealth is under **great stress**.\n\nThe main cause is uncomfortable to hear: our own *insensitivity* to the environment. We take what we want and forget the web that pays the price.\n\n*What would break if we kept ignoring it?* The very library we've barely begun to read.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 9, 'html_animation', $lj${"title":"TAKEN FOR GRANTED, UNDER STRESS","caption":"The variety we ignore is quietly fading — the leaves wilt, the colours drain.","html":"<div style=\"background:#f8fafc;padding:20px 12px;border-radius:12px;text-align:center;\">\n  <style>\n    @keyframes geoWilt { 0%,20%{fill:#16a34a;opacity:1} 80%,100%{fill:#a1887f;opacity:0.5} }\n    .geo-leaf { animation: geoWilt 4s ease-in-out infinite alternate; }\n  </style>\n  <svg viewBox=\"0 0 300 90\" style=\"max-width:320px;width:100%\" font-family=\"sans-serif\">\n    <g class=\"geo-leaf\">\n      <ellipse cx=\"50\" cy=\"45\" rx=\"13\" ry=\"22\"/>\n      <ellipse cx=\"110\" cy=\"45\" rx=\"13\" ry=\"22\"/>\n      <ellipse cx=\"170\" cy=\"45\" rx=\"13\" ry=\"22\"/>\n      <ellipse cx=\"230\" cy=\"45\" rx=\"13\" ry=\"22\"/>\n    </g>\n  </svg>\n</div>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 10, 'mcq', $lj${"question":"When scientists say India's biodiversity may be 'twice or thrice' what we know, what do they mean?","options":[{"id":"a","text":"India's wildlife is growing two or three times bigger each year.","is_correct":false,"rationale":"It's not about populations *growing*. It's about how many species exist that we haven't yet identified."},{"id":"b","text":"Many more species likely exist here than have been discovered and named so far.","is_correct":true,"rationale":"Right — the known species may be only a fraction; the true count could be two or three times higher, still undiscovered."},{"id":"c","text":"Indian species are two or three times larger than species elsewhere.","is_correct":false,"rationale":"Nothing to do with size. It's about the *number* of species yet to be discovered."},{"id":"d","text":"Two or three species go extinct every year.","is_correct":false,"rationale":"That's a different (grim) idea. The 'twice or thrice' figure is about undiscovered diversity."}],"xp":10}$lj$::jsonb, 10, true),
    (v_lesson, 11, 'tap_to_match', $lj${"prompt":"Match each term to what it means.","left":[{"id":"l1","label":"Flora"},{"id":"l2","label":"Fauna"},{"id":"l3","label":"'Twice or thrice'"},{"id":"l4","label":"Insensitivity to the environment"}],"right":[{"id":"r1","label":"Plant life"},{"id":"r2","label":"Animal life"},{"id":"r3","label":"Species still to be discovered"},{"id":"r4","label":"The main reason biodiversity is under stress"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]}$lj$::jsonb, 10, true),
    (v_lesson, 12, 'exercise', $lj${"instruction":"Find one **story, song, festival, or custom** from your region that shows a respectful or harmonious relationship between people and nature (a sacred tree, a protected animal, a harvest festival, a folk tale).\n\nOn paper, note it down. Then type the name of it and the plant or animal it honours below.\n","tool":"pencil","placeholder":"In my region, ___ honours the ___."}$lj$::jsonb, 15, true),
    (v_lesson, 13, 'fill_in_the_blank', $lj${"prompt":"Lock in the terms.","template":"India is among the world's richest in {{blank-1}} (plant life) and {{blank-2}} (animal life).\n","answers":[{"id":"blank-1","accepted":["flora","Flora"]},{"id":"blank-2","accepted":["fauna","Fauna"]}]}$lj$::jsonb, 10, true),
    (v_lesson, 14, 'reflection', $lj${"prompt":"Most of India's species are still undiscovered — yet many may be under threat before we ever know them. How does it feel to think a species could vanish before anyone names it?\n\nNo right answer.\n","placeholder":"The idea that..."}$lj$::jsonb, 5, true),
    (v_lesson, 15, 'checkpoint', $lj${"title":"You grasp how much living wealth India holds — and that it's at risk.","summary":"India carries one of the planet's richest libraries of life — flora and fauna woven into our food, faith, and songs, with far more species still undiscovered than known. And it's under real stress from our own carelessness.\n\nWhich raises the blunt question this course has been building to: *why* exactly should we spend effort and money to save it? What do we actually lose if biodiversity goes? That's the next lesson.\n","xp":0}$lj$::jsonb, 0, true);
  INSERT INTO lessons (course_id, slug, translations, order_index, estimated_minutes, xp_reward, format, is_published)
  INSERT INTO lesson_turns (lesson_id, order_index, turn_type, content, xp_reward, is_required) VALUES
    (v_lesson, 1, 'tutor_message', $lj${"text":"Here's a fair question to ask out loud: why spend money saving a frog you'll never even see?\n\nThe honest answer turns out to be about *you*, not the frog. Conservation isn't charity for animals. Let me show you why.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 2, 'tutor_message', $lj${"text":"First, the urgency. Wildlife populations and forests are in **rapid decline** — which is exactly why conservation has become *essential*.\n\nBut \"save nature\" stays a slogan until you can say *why* in concrete terms. There are three solid reasons. None of them is about cuteness.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 3, 'tutor_message', $lj${"text":"**Reason 1 — our life-support systems.**\n\nConservation preserves the ecological diversity that keeps our **air**, **water**, and **soil** working. The web is the machinery that makes the planet livable. Break it, and the machine that cleans your air and water breaks too.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 4, 'svg_graphic', $lj${"title":"WHAT BIODIVERSITY HOLDS UP","caption":"Clean air, water, soil, and the food we grow — all rest on biodiversity as their foundation.","svg":"<svg viewBox=\"0 0 360 170\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <rect x=\"20\" y=\"44\" width=\"60\" height=\"78\" rx=\"4\" fill=\"#dbeafe\" stroke=\"#0f172a\" stroke-width=\"1.2\"/>\n  <text x=\"50\" y=\"88\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#1e3a8a\">AIR</text>\n  <rect x=\"106\" y=\"44\" width=\"60\" height=\"78\" rx=\"4\" fill=\"#cffafe\" stroke=\"#0f172a\" stroke-width=\"1.2\"/>\n  <text x=\"136\" y=\"88\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#0e7490\">WATER</text>\n  <rect x=\"192\" y=\"44\" width=\"60\" height=\"78\" rx=\"4\" fill=\"#fde68a\" stroke=\"#0f172a\" stroke-width=\"1.2\"/>\n  <text x=\"222\" y=\"88\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#92400e\">SOIL</text>\n  <rect x=\"278\" y=\"44\" width=\"62\" height=\"78\" rx=\"4\" fill=\"#dcfce7\" stroke=\"#0f172a\" stroke-width=\"1.2\"/>\n  <text x=\"309\" y=\"84\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#166534\">FOOD</text>\n  <text x=\"309\" y=\"98\" text-anchor=\"middle\" font-size=\"7\" fill=\"#166534\">+ crops</text>\n  <rect x=\"20\" y=\"130\" width=\"320\" height=\"28\" rx=\"4\" fill=\"#16a34a\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"180\" y=\"148\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"bold\" fill=\"#ffffff\">BIODIVERSITY</text>\n</svg>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 5, 'tutor_message', $lj${"text":"**Reason 2 — genetic diversity: the seed bank of the future.**\n\nConservation preserves the genetic variety of plants and animals — the raw material for *better growth and breeding*. Every wild relative of a crop is a spare gene we may desperately need when a new disease or a drought arrives.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 6, 'tutor_message', $lj${"text":"Make it concrete.\n\nIn **agriculture**, we *still* depend on **traditional crop varieties** — their genes carry resilience that modern hybrids often lack. And **fisheries** depend entirely on keeping **aquatic biodiversity** alive.\n\nLose the variety, and you lose the harvest — on land and at sea.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 7, 'html_animation', $lj${"title":"WHY VARIETY IS INSURANCE","caption":"When one crop variety fails, a different one survives — that's what genetic diversity buys us.","html":"<div style=\"background:#f8fafc;padding:18px 12px;border-radius:12px;text-align:center;\">\n  <style>\n    @keyframes geoFailSeed { 0%,30%{fill:#16a34a} 60%,100%{fill:#9ca3af} }\n    .geo-fail { animation: geoFailSeed 4s ease-in-out infinite alternate; }\n  </style>\n  <svg viewBox=\"0 0 300 96\" style=\"max-width:320px;width:100%\" font-family=\"sans-serif\">\n    <circle cx=\"50\" cy=\"38\" r=\"16\" class=\"geo-fail\" stroke=\"#0f172a\" stroke-width=\"1\"/>\n    <circle cx=\"110\" cy=\"38\" r=\"16\" fill=\"#16a34a\" stroke=\"#0f172a\" stroke-width=\"1\"/>\n    <circle cx=\"170\" cy=\"38\" r=\"16\" fill=\"#16a34a\" stroke=\"#0f172a\" stroke-width=\"1\"/>\n    <circle cx=\"230\" cy=\"38\" r=\"16\" fill=\"#16a34a\" stroke=\"#0f172a\" stroke-width=\"1\"/>\n    <text x=\"150\" y=\"80\" text-anchor=\"middle\" font-size=\"8\" fill=\"#475569\">one variety fails — the others still feed us</text>\n  </svg>\n</div>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 8, 'tutor_message', $lj${"text":"Put it together. *What would break if biodiversity went?*\n\nThree things fail at once: the cleaners of our air, water, and soil; the gene bank our farms quietly draw on; and the fish in the sea.\n\nSo conservation isn't sentimental. It's **self-preservation** — for us.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 9, 'mcq', $lj${"question":"Which best captures why conserving biodiversity matters to humans?","options":[{"id":"a","text":"Mainly so we have beautiful animals to look at and visit.","is_correct":false,"rationale":"Beauty and tourism are nice, but the chapter's reasons are far more basic — survival, not scenery."},{"id":"b","text":"It preserves our life-support systems (air, water, soil) and the genetic diversity our farming and fisheries depend on.","is_correct":true,"rationale":"Exactly. Conservation protects ecological *and* genetic diversity — the systems and gene banks we live off."},{"id":"c","text":"Because the law says we must, and there's no deeper reason.","is_correct":false,"rationale":"The law exists *because* of the deeper reasons — life-support systems and genetic diversity."},{"id":"d","text":"Only to protect a few famous animals like the tiger.","is_correct":false,"rationale":"Modern conservation focuses on whole biodiversity, not just a few species — and the reasons reach far beyond any one animal."}],"xp":10}$lj$::jsonb, 10, true),
    (v_lesson, 10, 'tap_to_match', $lj${"prompt":"Match what conservation preserves to why it matters to us.","left":[{"id":"l1","label":"Ecological diversity"},{"id":"l2","label":"Genetic diversity"},{"id":"l3","label":"Traditional crop varieties"},{"id":"l4","label":"Aquatic biodiversity"}],"right":[{"id":"r1","label":"Keeps our air, water, and soil working"},{"id":"r2","label":"Backup genes for breeding better species"},{"id":"r3","label":"What our agriculture still relies on"},{"id":"r4","label":"What our fisheries depend on"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]}$lj$::jsonb, 10, true),
    (v_lesson, 11, 'exercise', $lj${"instruction":"Pick one food you ate today — rice, fish, a fruit, dal.\n\nOn paper, trace it back: which living things and which *variety* or *species* made it possible? What would happen to that food if its biodiversity vanished? Type the food and your one-line answer below.\n","tool":"pencil","placeholder":"My ___ depends on ___; without it..."}$lj$::jsonb, 15, true),
    (v_lesson, 12, 'fill_in_the_blank', $lj${"prompt":"Lock in the two reasons.","template":"Conservation protects our life-support systems (air, water, soil) and the {{blank-1}} diversity we need to breed better crops; our {{blank-2}} depend on aquatic biodiversity.\n","answers":[{"id":"blank-1","accepted":["genetic","Genetic"]},{"id":"blank-2","accepted":["fisheries","Fisheries","fishery"]}]}$lj$::jsonb, 10, true),
    (v_lesson, 13, 'reflection', $lj${"prompt":"Conservation is \"self-preservation, not charity.\" Does framing it that way make you take it more seriously — or does something feel lost when we only value nature for what it does *for us*?\n\nNo right answer.\n","placeholder":"Framed as self-preservation, I..."}$lj$::jsonb, 5, true),
    (v_lesson, 14, 'checkpoint', $lj${"title":"You can give concrete reasons biodiversity is worth saving.","summary":"Conservation guards our life-support systems — air, water, soil — and the genetic diversity our farms and fisheries quietly depend on. It's not charity for animals; it's protection for us.\n\nSo we know *why*. Now the harder question: *how* does an entire country actually protect its forests and wildlife? It began, in 1972, with a single powerful law. That's where the next course starts.\n","xp":0}$lj$::jsonb, 0, true);
  INSERT INTO lessons (course_id, slug, translations, order_index, estimated_minutes, xp_reward, format, is_published)
  INSERT INTO lesson_turns (lesson_id, order_index, turn_type, content, xp_reward, is_required) VALUES
    (v_lesson, 1, 'tutor_message', $lj${"text":"When a mining company came for the Sariska forest in Rajasthan, it wasn't the police who turned them back.\n\nIt was the **villagers** — armed with nothing but a law and their own resolve. And they won.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 2, 'tutor_message', $lj${"text":"Conservation isn't a new government idea in India. Forests have *always* been **home** to traditional communities.\n\nAnd across the country, those communities are fighting to protect their forests — because they understand that their own *long-term livelihood* depends on it.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 3, 'tutor_message', $lj${"text":"Take **Sariska Tiger Reserve, Rajasthan.** Villagers fought off **mining** by citing the **Wildlife Protection Act** — turning the law from the last course into their own weapon.\n\nIn many places, villagers protect habitats *themselves* — sometimes even rejecting government involvement entirely.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 4, 'tutor_message', $lj${"text":"Then there's the **Bhairodev Dakav 'Sonchuri'.**\n\nIn Alwar district, Rajasthan, the people of **five villages** declared **1,200 hectares** of forest their *own* sanctuary — with their *own* rules: no hunting, and no outside encroachment. A people's protected area, run entirely by the people.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 5, 'media', $lj${"kind":"image","url":"https://dfdocnhhxrnvblbwwium.supabase.co/storage/v1/object/public/lesson-images/b-class-10-geography-ch02-forest-and-wildlife-resources/c3l1-chipko.png","caption":"The Chipko movement: villagers wrapping their arms around trees to stop them being felled.","aspect_ratio":1.7778}$lj$::jsonb, 0, true),
    (v_lesson, 6, 'svg_graphic', $lj${"title":"THE FOREST'S NEIGHBOURS","caption":"Across India, the communities living beside a forest became its guardians.","svg":"<svg viewBox=\"0 0 360 180\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <line x1=\"180\" y1=\"92\" x2=\"80\" y2=\"40\" stroke=\"#cbd5e1\" stroke-width=\"1.5\"/>\n  <line x1=\"180\" y1=\"92\" x2=\"290\" y2=\"40\" stroke=\"#cbd5e1\" stroke-width=\"1.5\"/>\n  <line x1=\"180\" y1=\"92\" x2=\"180\" y2=\"150\" stroke=\"#cbd5e1\" stroke-width=\"1.5\"/>\n  <circle cx=\"155\" cy=\"92\" r=\"16\" fill=\"#16a34a\"/><rect x=\"152\" y=\"100\" width=\"6\" height=\"12\" fill=\"#92400e\"/>\n  <circle cx=\"185\" cy=\"86\" r=\"20\" fill=\"#15803d\"/><rect x=\"182\" y=\"98\" width=\"7\" height=\"14\" fill=\"#92400e\"/>\n  <circle cx=\"210\" cy=\"94\" r=\"15\" fill=\"#16a34a\"/><rect x=\"207\" y=\"101\" width=\"6\" height=\"11\" fill=\"#92400e\"/>\n  <rect x=\"14\" y=\"22\" width=\"132\" height=\"34\" rx=\"5\" fill=\"#fef9c3\" stroke=\"#0f172a\" stroke-width=\"1\"/>\n  <text x=\"80\" y=\"38\" text-anchor=\"middle\" font-size=\"9\" font-weight=\"bold\" fill=\"#854d0e\">Sariska</text>\n  <text x=\"80\" y=\"50\" text-anchor=\"middle\" font-size=\"8\" fill=\"#475569\">villagers fought mining</text>\n  <rect x=\"220\" y=\"22\" width=\"132\" height=\"34\" rx=\"5\" fill=\"#fef9c3\" stroke=\"#0f172a\" stroke-width=\"1\"/>\n  <text x=\"286\" y=\"38\" text-anchor=\"middle\" font-size=\"9\" font-weight=\"bold\" fill=\"#854d0e\">Bhairodev Sonchuri</text>\n  <text x=\"286\" y=\"50\" text-anchor=\"middle\" font-size=\"8\" fill=\"#475569\">5 villages, 1,200 hectares</text>\n  <rect x=\"114\" y=\"154\" width=\"132\" height=\"22\" rx=\"5\" fill=\"#fef9c3\" stroke=\"#0f172a\" stroke-width=\"1\"/>\n  <text x=\"180\" y=\"168\" text-anchor=\"middle\" font-size=\"9\" font-weight=\"bold\" fill=\"#854d0e\">Chipko — hugged the trees</text>\n</svg>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 7, 'tutor_message', $lj${"text":"And the most famous of all — the **Chipko movement** in the Himalayas.\n\nVillagers literally *clung to the trees* to stop them being cut (*chipko* means \"to hug\" or \"to cling\"). It didn't just halt deforestation in many areas — it *proved* that **community afforestation with indigenous species** can succeed on a huge scale.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 8, 'html_animation', $lj${"title":"CHIPKO — CLING TO THE TREE","caption":"When villagers wrapped their arms around the trees, the axe had to stop.","html":"<div style=\"background:#f8fafc;padding:18px 12px;border-radius:12px;text-align:center;\">\n  <style>\n    @keyframes geoAxe { 0%,40%{transform:translateX(0);opacity:1} 60%,100%{transform:translateX(-26px);opacity:0.25} }\n    @keyframes geoArm { 0%,20%{opacity:0} 45%,100%{opacity:1} }\n    .geo-axe{animation:geoAxe 4s ease-in-out infinite alternate}\n    .geo-arm{animation:geoArm 4s infinite alternate}\n  </style>\n  <svg viewBox=\"0 0 300 130\" style=\"max-width:300px;width:100%\" font-family=\"sans-serif\">\n    <rect x=\"146\" y=\"40\" width=\"10\" height=\"70\" fill=\"#92400e\"/>\n    <circle cx=\"151\" cy=\"36\" r=\"22\" fill=\"#16a34a\"/>\n    <path class=\"geo-arm\" d=\"M120,80 Q151,66 182,80\" stroke=\"#0f172a\" stroke-width=\"4\" fill=\"none\"/>\n    <circle class=\"geo-arm\" cx=\"116\" cy=\"82\" r=\"7\" fill=\"#fcd34d\" stroke=\"#0f172a\" stroke-width=\"1\"/>\n    <circle class=\"geo-arm\" cx=\"186\" cy=\"82\" r=\"7\" fill=\"#fcd34d\" stroke=\"#0f172a\" stroke-width=\"1\"/>\n    <g class=\"geo-axe\"><rect x=\"232\" y=\"60\" width=\"28\" height=\"5\" fill=\"#475569\"/><polygon points=\"232,54 232,72 220,63\" fill=\"#94a3b8\"/></g>\n    <text x=\"150\" y=\"124\" text-anchor=\"middle\" font-size=\"8\" fill=\"#166534\">arms around the trunk — the axe retreats</text>\n  </svg>\n</div>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 9, 'tutor_message', $lj${"text":"Notice the pattern in every story.\n\nIt was the people who *live beside* the forest — not a distant rule — who saved it. The forest's best guardians turn out to be its **neighbours**.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 10, 'mcq', $lj${"question":"How did the villagers at Sariska stop mining inside the tiger reserve?","options":[{"id":"a","text":"By paying the mining company to leave.","is_correct":false,"rationale":"There was no payment. They used a legal route, not money."},{"id":"b","text":"By citing the Wildlife Protection Act to challenge the mining.","is_correct":true,"rationale":"Exactly — the villagers turned the 1972 law into their tool to defend the reserve."},{"id":"c","text":"By waiting for the central government to send the army.","is_correct":false,"rationale":"The point of the story is that the *community* acted, not a distant authority."},{"id":"d","text":"By clearing the forest themselves first.","is_correct":false,"rationale":"That's the opposite of conservation — they were protecting the forest, not clearing it."}],"xp":10}$lj$::jsonb, 10, true),
    (v_lesson, 11, 'tap_to_match', $lj${"prompt":"Match each community action to what it was.","left":[{"id":"l1","label":"Sariska, Rajasthan"},{"id":"l2","label":"Bhairodev Dakav 'Sonchuri'"},{"id":"l3","label":"Chipko movement"}],"right":[{"id":"r1","label":"Villagers fought mining using the Wildlife Protection Act"},{"id":"r2","label":"Five villages declared 1,200 hectares their own sanctuary"},{"id":"r3","label":"People clung to trees to stop deforestation in the Himalayas"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"]]}$lj$::jsonb, 10, true),
    (v_lesson, 12, 'exercise', $lj${"instruction":"Think of one way *people you know* — a village, a family, a temple, a school — protect a tree, an animal, a pond, or a patch of green near them.\n\nOn paper, describe it in two lines. Then type what is protected and who protects it below.\n","tool":"pencil","placeholder":"Near me, ___ protect the ___."}$lj$::jsonb, 15, true),
    (v_lesson, 13, 'fill_in_the_blank', $lj${"prompt":"Lock in two community actions.","template":"At Sariska, villagers stopped mining by citing the {{blank-1}} Act; in the Chipko movement, people {{blank-2}} the trees to save them.\n","answers":[{"id":"blank-1","accepted":["Wildlife Protection","wildlife protection","Wildlife (Protection)"]},{"id":"blank-2","accepted":["hugged","clung to","hugged","embraced"]}]}$lj$::jsonb, 10, true),
    (v_lesson, 14, 'reflection', $lj${"prompt":"The villagers at Sariska and Chipko protected forests they didn't legally \"own\". What do you think made them fight so hard for something that wasn't theirs on paper?\n\nNo right answer.\n","placeholder":"I think they fought because..."}$lj$::jsonb, 5, true),
    (v_lesson, 15, 'checkpoint', $lj${"title":"You can show how communities themselves defend India's forests.","summary":"From Sariska's fight against mining, to a people's sanctuary at Bhairodev, to the tree-hugging Chipko movement — again and again, the forest's neighbours became its guardians.\n\nBut defending a forest is only half of it. The other half is *living* off it without destroying it. How do communities farm and harvest in partnership with nature? That's the next lesson.\n","xp":0}$lj$::jsonb, 0, true);
  INSERT INTO lessons (course_id, slug, translations, order_index, estimated_minutes, xp_reward, format, is_published)
  INSERT INTO lesson_turns (lesson_id, order_index, turn_type, content, xp_reward, is_required) VALUES
    (v_lesson, 1, 'tutor_message', $lj${"text":"Here's a strange-sounding idea: the way to *save* a forest might be to let the people nearby make a living from it — without destroying it.\n\nTwo Indian movements proved it actually works.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 2, 'tutor_message', $lj${"text":"**Beej Bachao Andolan** (in Tehri) and **Navdanya** are farmers' and citizens' groups. They proved something powerful:\n\nyou can grow *diverse* crops, *without* synthetic chemicals, and still make it **economically viable**.\n\n(*Beej Bachao* means \"save the seeds\" — protecting traditional seed diversity.) Farming *with* nature, not against it.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 3, 'tutor_message', $lj${"text":"Then there's **Joint Forest Management (JFM)** — a formal partnership between the Forest Department and local villages.\n\nIt's been in formal existence since **1988**, when **Odisha** passed the very first resolution for it.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 4, 'svg_graphic', $lj${"title":"THE JFM DEAL","caption":"Villages protect and restore degraded forest; in return, the forest provides for them.","svg":"<svg viewBox=\"0 0 360 156\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <rect x=\"20\" y=\"48\" width=\"110\" height=\"60\" rx=\"6\" fill=\"#dbeafe\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"75\" y=\"74\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#1e3a8a\">VILLAGE</text>\n  <text x=\"75\" y=\"90\" text-anchor=\"middle\" font-size=\"8\" fill=\"#475569\">local institution</text>\n  <rect x=\"230\" y=\"48\" width=\"110\" height=\"60\" rx=\"6\" fill=\"#dcfce7\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"285\" y=\"72\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#166534\">DEGRADED</text>\n  <text x=\"285\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#166534\">FOREST</text>\n  <line x1=\"130\" y1=\"64\" x2=\"226\" y2=\"64\" stroke=\"#16a34a\" stroke-width=\"2.5\"/>\n  <polygon points=\"226,64 214,59 214,69\" fill=\"#16a34a\"/>\n  <text x=\"178\" y=\"56\" text-anchor=\"middle\" font-size=\"8\" fill=\"#166534\">protect + restore</text>\n  <line x1=\"230\" y1=\"94\" x2=\"134\" y2=\"94\" stroke=\"#ca8a04\" stroke-width=\"2.5\"/>\n  <polygon points=\"134,94 146,89 146,99\" fill=\"#ca8a04\"/>\n  <text x=\"182\" y=\"112\" text-anchor=\"middle\" font-size=\"8\" fill=\"#854d0e\">produce + timber share</text>\n</svg>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 5, 'tutor_message', $lj${"text":"Here's the deal, exactly.\n\nLocal **village institutions** take on protecting **degraded forest land** (still managed by the forest department). In return, they earn real **benefits**: *non-timber forest produce*, plus a *share of the timber* harvested through their own \"successful protection.\"\n\nProtect the forest, and the forest pays you back. Both sides win.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 6, 'tutor_message', $lj${"text":"The clear lesson from India's whole story — of *destruction* and of *repair* — is this:\n\nlocal communities **everywhere** have to be involved in managing natural resources. There's no lasting conservation that leaves out the people who live with the forest.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 7, 'tutor_message', $lj${"text":"But a caution comes with it. We're still a long way from communities being at the *centre* of decisions.\n\nSo here's the test for *any* development or economic activity — it must be all three at once:\n\n- **people-centric**\n- **environment-friendly**\n- **economically rewarding**\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 8, 'html_animation', $lj${"title":"A TWO-WAY PARTNERSHIP","caption":"Protection flows one way, benefits flow back — that's what makes JFM last.","html":"<div style=\"background:#f8fafc;padding:18px 12px;border-radius:12px;text-align:center;\">\n  <style>\n    @keyframes geoGive { 0%,100%{opacity:.25} 30%,45%{opacity:1} }\n    @keyframes geoGet { 0%,100%{opacity:.25} 65%,80%{opacity:1} }\n    .geo-give{animation:geoGive 4s infinite} .geo-get{animation:geoGet 4s infinite}\n  </style>\n  <svg viewBox=\"0 0 300 110\" style=\"max-width:320px;width:100%\" font-family=\"sans-serif\">\n    <circle cx=\"50\" cy=\"55\" r=\"26\" fill=\"#bfdbfe\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n    <text x=\"50\" y=\"59\" text-anchor=\"middle\" font-size=\"9\" font-weight=\"bold\" fill=\"#1e3a8a\">village</text>\n    <circle cx=\"250\" cy=\"55\" r=\"26\" fill=\"#bbf7d0\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n    <text x=\"250\" y=\"59\" text-anchor=\"middle\" font-size=\"9\" font-weight=\"bold\" fill=\"#166534\">forest</text>\n    <g class=\"geo-give\"><line x1=\"80\" y1=\"42\" x2=\"218\" y2=\"42\" stroke=\"#16a34a\" stroke-width=\"3\"/><polygon points=\"218,42 206,37 206,47\" fill=\"#16a34a\"/></g>\n    <g class=\"geo-get\"><line x1=\"220\" y1=\"70\" x2=\"82\" y2=\"70\" stroke=\"#ca8a04\" stroke-width=\"3\"/><polygon points=\"82,70 94,65 94,75\" fill=\"#ca8a04\"/></g>\n  </svg>\n</div>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 9, 'mcq', $lj${"question":"Which of these conservation strategies does NOT directly involve community participation?","options":[{"id":"a","text":"Joint Forest Management","is_correct":false,"rationale":"JFM is built entirely on village institutions protecting and restoring forest — community participation is its core."},{"id":"b","text":"Beej Bachao Andolan","is_correct":false,"rationale":"Beej Bachao Andolan is a farmers' movement — community participation through and through."},{"id":"c","text":"Chipko Movement","is_correct":false,"rationale":"Chipko was villagers physically protecting trees — about as community-driven as it gets."},{"id":"d","text":"Demarcation of wildlife sanctuaries","is_correct":true,"rationale":"Correct. Demarcating sanctuaries is a government/administrative act — it doesn't directly depend on community participation the way the others do."}],"xp":10}$lj$::jsonb, 10, true),
    (v_lesson, 10, 'tap_to_match', $lj${"prompt":"Match each effort to what it is.","left":[{"id":"l1","label":"Beej Bachao Andolan"},{"id":"l2","label":"Navdanya"},{"id":"l3","label":"Joint Forest Management"},{"id":"l4","label":"1988, Odisha"}],"right":[{"id":"r1","label":"Saving traditional seeds, in Tehri"},{"id":"r2","label":"Diverse crops without synthetic chemicals"},{"id":"r3","label":"Villages restore degraded forest for a share of produce"},{"id":"r4","label":"When and where JFM formally began"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]}$lj$::jsonb, 10, true),
    (v_lesson, 11, 'exercise', $lj${"instruction":"Think of one small \"farming with nature\" step you (or your family) could actually take — composting kitchen waste, growing a chemical-free pot of herbs, saving seeds, planting a native tree.\n\nOn paper, write your idea and one benefit it brings. Type it below.\n","tool":"pencil","placeholder":"I could ___ , which would..."}$lj$::jsonb, 15, true),
    (v_lesson, 12, 'fill_in_the_blank', $lj${"prompt":"Lock in where JFM began.","template":"Joint Forest Management formally began in {{blank-1}}, when {{blank-2}} passed the first resolution.\n","answers":[{"id":"blank-1","accepted":["1988"]},{"id":"blank-2","accepted":["Odisha","odisha"]}]}$lj$::jsonb, 10, true),
    (v_lesson, 13, 'reflection', $lj${"prompt":"The three-part test was: people-centric, environment-friendly, *and* economically rewarding. Why do you think a project usually fails if it's missing just one of the three?\n\nNo right answer.\n","placeholder":"If a project skips ___, then..."}$lj$::jsonb, 5, true),
    (v_lesson, 14, 'checkpoint', $lj${"title":"You can explain how communities farm and restore in partnership with nature.","summary":"Beej Bachao Andolan and Navdanya showed chemical-free, diverse farming is viable; Joint Forest Management (since 1988, Odisha) turned villages into forest restorers who share in the rewards. The rule that holds it together: development must be people-centric, environment-friendly, and economically rewarding — all three.\n\nBut the oldest form of community conservation in India needed no law and no contract at all. It runs on something deeper: reverence. Meet the sacred groves — and the close of this chapter.\n","xp":0}$lj$::jsonb, 0, true);
  INSERT INTO lessons (course_id, slug, translations, order_index, estimated_minutes, xp_reward, format, is_published)
  INSERT INTO lesson_turns (lesson_id, order_index, turn_type, content, xp_reward, is_required) VALUES
    (v_lesson, 1, 'tutor_message', $lj${"text":"Long before any Wildlife Act, some forests in India were already untouchable.\n\nNot because of a law. Because of *faith*. Cut a tree there and you weren't breaking a rule — you were committing a sin.\n\nWelcome to the **sacred groves**.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 2, 'tutor_message', $lj${"text":"Across India, **nature worship** — an age-old tribal belief that *all creations of nature must be protected* — preserved entire forests in their **virgin, pristine form**.\n\nThese are the **Sacred Groves**: the forests of gods and goddesses.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 3, 'tutor_message', $lj${"text":"The rule is simple and absolute: these patches are left **untouched**, and *any* interference is banned.\n\nFaith did what fences and rangers often couldn't — it kept whole forests intact for centuries.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 4, 'tutor_message', $lj${"text":"It reaches down to single trees, too. Communities have revered particular species from time immemorial:\n\n- the **Mundas and Santhal** of Chota Nagpur worship the **mahua** and **kadamba** trees.\n- tribals of **Odisha and Bihar** worship the **tamarind** and **mango** at weddings.\n- the **peepal** and **banyan** are sacred to many across India.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 5, 'media', $lj${"kind":"image","url":"https://dfdocnhhxrnvblbwwium.supabase.co/storage/v1/object/public/lesson-images/b-class-10-geography-ch02-forest-and-wildlife-resources/c3l3-sacred-grove.png","caption":"A sacred grove — a patch of forest left untouched for generations in the name of the divine.","aspect_ratio":1.7778}$lj$::jsonb, 0, true),
    (v_lesson, 6, 'svg_graphic', $lj${"title":"A SACRED GROVE","caption":"Protected by reverence, not fences — peepal, banyan, mahua, kadamba, tamarind, mango.","svg":"<svg viewBox=\"0 0 360 180\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <ellipse cx=\"180\" cy=\"84\" rx=\"130\" ry=\"66\" fill=\"#fffbeb\" stroke=\"#ca8a04\" stroke-width=\"2.5\" stroke-dasharray=\"6 4\"/>\n  <circle cx=\"148\" cy=\"82\" r=\"20\" fill=\"#15803d\"/><rect x=\"145\" y=\"92\" width=\"6\" height=\"16\" fill=\"#92400e\"/>\n  <circle cx=\"186\" cy=\"72\" r=\"25\" fill=\"#16a34a\"/><rect x=\"182\" y=\"85\" width=\"7\" height=\"18\" fill=\"#92400e\"/>\n  <circle cx=\"220\" cy=\"86\" r=\"18\" fill=\"#15803d\"/><rect x=\"217\" y=\"95\" width=\"6\" height=\"14\" fill=\"#92400e\"/>\n  <text x=\"180\" y=\"138\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#854d0e\">SACRED GROVE</text>\n  <text x=\"180\" y=\"154\" text-anchor=\"middle\" font-size=\"8\" fill=\"#475569\">untouched · interference banned</text>\n</svg>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 7, 'tutor_message', $lj${"text":"Animals are protected this way too.\n\nTroops of **macaques and langurs** live around many temples — fed daily, treated as part of the temple's devotees. And in and around the **Bishnoi villages** of Rajasthan, herds of **blackbuck (chinkara), nilgai, and peacocks** are simply part of the community — and *nobody harms them*.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 8, 'media', $lj${"kind":"image","url":"https://dfdocnhhxrnvblbwwium.supabase.co/storage/v1/object/public/lesson-images/b-class-10-geography-ch02-forest-and-wildlife-resources/c3l3-blackbuck-bishnoi.png","caption":"Blackbuck and peacock grazing unafraid near a Bishnoi village — wildlife protected by faith.","aspect_ratio":1.7778}$lj$::jsonb, 0, true),
    (v_lesson, 9, 'html_animation', $lj${"title":"PROTECTED BY REVERENCE","caption":"Within the sacred grove, the trees and animals rest safe — guarded by belief.","html":"<div style=\"background:#f8fafc;padding:18px 12px;border-radius:12px;text-align:center;\">\n  <style>\n    @keyframes geoHalo { 0%,100%{opacity:.25;r:64} 50%{opacity:.7;r:70} }\n    .geo-halo{animation:geoHalo 4s ease-in-out infinite}\n  </style>\n  <svg viewBox=\"0 0 240 140\" style=\"max-width:260px;width:100%\" font-family=\"sans-serif\">\n    <circle class=\"geo-halo\" cx=\"120\" cy=\"70\" r=\"64\" fill=\"none\" stroke=\"#f59e0b\" stroke-width=\"3\"/>\n    <circle cx=\"100\" cy=\"64\" r=\"18\" fill=\"#16a34a\"/><rect x=\"97\" y=\"74\" width=\"6\" height=\"14\" fill=\"#92400e\"/>\n    <circle cx=\"140\" cy=\"60\" r=\"20\" fill=\"#15803d\"/><rect x=\"137\" y=\"72\" width=\"6\" height=\"14\" fill=\"#92400e\"/>\n    <circle cx=\"110\" cy=\"100\" r=\"7\" fill=\"#a16207\"/>\n    <circle cx=\"135\" cy=\"102\" r=\"7\" fill=\"#a16207\"/>\n    <text x=\"120\" y=\"132\" text-anchor=\"middle\" font-size=\"8\" fill=\"#854d0e\">trees and animals, safe inside</text>\n  </svg>\n</div>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 10, 'tutor_message', $lj${"text":"The Buddha, in 487 B.C., caught the whole spirit of it:\n\n*\"The tree is a peculiar organism of unlimited kindness and benevolence... It affords protection to all beings, offering shade even to the axemen who destroy it.\"*\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 11, 'tutor_message', $lj${"text":"And that's the thread running through this entire chapter.\n\nFrom the Wildlife Act, to Project Tiger, to joint forest management, to the sacred groves — *forests and wildlife survive best when the people who live with them are at the centre of protecting them.*\n\nLaw helps. Faith helps. But **community** is the heart of it.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 12, 'mcq', $lj${"question":"What keeps a sacred grove protected?","options":[{"id":"a","text":"Paid forest guards posted at its edges.","is_correct":false,"rationale":"Sacred groves aren't kept by paid guards — they're kept by belief."},{"id":"b","text":"A community's religious belief that the forest is sacred and must not be touched.","is_correct":true,"rationale":"Exactly. Nature worship treats these forests as the homes of gods — interference is banned by faith, not by fences."},{"id":"c","text":"A central government law passed in 1972.","is_correct":false,"rationale":"Sacred groves are far older than any modern law — they're protected by tradition, not legislation."},{"id":"d","text":"A fence and a ticket gate.","is_correct":false,"rationale":"No fence required. The boundary is one of reverence, respected by the whole community."}],"xp":10}$lj$::jsonb, 10, true),
    (v_lesson, 13, 'tap_to_match', $lj${"prompt":"Match each tradition to what it protects.","left":[{"id":"l1","label":"Mundas and Santhal"},{"id":"l2","label":"Bishnoi villages, Rajasthan"},{"id":"l3","label":"Sacred groves"},{"id":"l4","label":"Around many temples"}],"right":[{"id":"r1","label":"The mahua and kadamba trees"},{"id":"r2","label":"Blackbuck, nilgai, and peacocks"},{"id":"r3","label":"Virgin forests of gods and goddesses"},{"id":"r4","label":"Macaques and langurs"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]}$lj$::jsonb, 10, true),
    (v_lesson, 14, 'exercise', $lj${"instruction":"Write a short note (4–5 lines) on any practice — at home, in your community, or one you'd like to start — that conserves and protects the environment around you.\n\nThen type one practice you wrote about below.\n","tool":"pencil","placeholder":"One practice that protects nature around me is..."}$lj$::jsonb, 15, true),
    (v_lesson, 15, 'fill_in_the_blank', $lj${"prompt":"Lock in the closing terms.","template":"Virgin forests preserved through nature worship are called {{blank-1}} groves, and the {{blank-2}} of Rajasthan protect the blackbuck as part of their community.\n","answers":[{"id":"blank-1","accepted":["sacred","Sacred"]},{"id":"blank-2","accepted":["Bishnoi","bishnoi","Bishnois"]}]}$lj$::jsonb, 10, true),
    (v_lesson, 16, 'reflection', $lj${"prompt":"Across this whole chapter — the web of life, the laws, Project Tiger, the communities, the sacred groves — what's the one idea you'll carry with you about protecting nature? Name it, and why it stuck.\n\nNo right answer. This is your takeaway.\n","placeholder":"The idea I'm keeping is..."}$lj$::jsonb, 5, true),
    (v_lesson, 17, 'checkpoint', $lj${"title":"The whole chapter is yours: biodiversity, protection, and community.","summary":"Sacred groves and the Bishnoi show the oldest conservation of all — protection by reverence, needing no law at all. And that completes the chapter.\n\nYou learned that we are one strand in a web of life we depend on for air, water, and soil; you can say why conservation is self-preservation, not charity; you know how India defends its wildlife through the 1972 Act, Project Tiger, and the three classes of forest; and you've seen that the deepest protection of all comes from communities — from Chipko and joint forest management to the sacred groves.\n\nThe clear lesson, as the Buddha knew: care for the tree, and it shelters everyone — even, in time, the rest of us.\n","xp":0}$lj$::jsonb, 0, true);
  INSERT INTO lessons (course_id, slug, translations, order_index, estimated_minutes, xp_reward, format, is_published)
  INSERT INTO lesson_turns (lesson_id, order_index, turn_type, content, xp_reward, is_required) VALUES
    (v_lesson, 1, 'tutor_message', $lj${"text":"For most of history, killing a tiger was a *trophy*. Something to be photographed with, not punished for.\n\nOne year changed that across India. The year was **1972**. Here's what happened.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 2, 'tutor_message', $lj${"text":"By the 1960s and 70s, wildlife was vanishing fast. Conservationists pushed hard for a *national* wildlife protection programme.\n\nThe result was the **Indian Wildlife (Protection) Act, 1972** — and it gave India, for the first time, real legal teeth to defend its wild creatures.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 3, 'tutor_message', $lj${"text":"Think of the Act as a **shield** with three edges:\n\n- **Ban hunting** of endangered species.\n- **Protect their habitats** in law.\n- **Restrict the trade** in wildlife.\n\nIt also published an all-India **list of protected species** — naming exactly who the shield covered.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 4, 'media', $lj${"kind":"image","url":"https://dfdocnhhxrnvblbwwium.supabase.co/storage/v1/object/public/lesson-images/b-class-10-geography-ch02-forest-and-wildlife-resources/c2l1-protected-wildlife.png","caption":"Species the law steps in to protect: tiger, one-horned rhino, Asiatic lion, snow leopard.","aspect_ratio":1.7778}$lj$::jsonb, 0, true),
    (v_lesson, 5, 'svg_graphic', $lj${"title":"WILDLIFE PROTECTION ACT, 1972","caption":"One law, three protections: ban hunting, protect habitats, restrict trade.","svg":"<svg viewBox=\"0 0 360 180\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <path d=\"M180,14 L312,50 L312,104 C312,150 250,168 180,176 C110,168 48,150 48,104 L48,50 Z\" fill=\"#dcfce7\" stroke=\"#166534\" stroke-width=\"2.5\"/>\n  <text x=\"180\" y=\"44\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#166534\">THE 1972 SHIELD</text>\n  <line x1=\"74\" y1=\"56\" x2=\"286\" y2=\"56\" stroke=\"#86efac\" stroke-width=\"1.5\"/>\n  <text x=\"180\" y=\"78\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#0f172a\">Ban hunting</text>\n  <line x1=\"90\" y1=\"90\" x2=\"270\" y2=\"90\" stroke=\"#86efac\" stroke-width=\"1\"/>\n  <text x=\"180\" y=\"110\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#0f172a\">Protect habitats</text>\n  <line x1=\"90\" y1=\"122\" x2=\"270\" y2=\"122\" stroke=\"#86efac\" stroke-width=\"1\"/>\n  <text x=\"180\" y=\"142\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#0f172a\">Restrict trade</text>\n</svg>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 6, 'tutor_message', $lj${"text":"With the Act in place, central and state governments set up **national parks** and **wildlife sanctuaries** — protected zones where the shield is strongest, and where wild populations could recover.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 7, 'tutor_message', $lj${"text":"The government also launched **projects for specific animals** on the very brink:\n\nthe **tiger**, the **one-horned rhinoceros**, the **Kashmir stag** (hangul), three crocodiles — freshwater, saltwater, and the **gharial** — and the **Asiatic lion**.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 8, 'tutor_message', $lj${"text":"More recently, the shield widened to cover the **Indian elephant**, the **black buck** (chinkara), the **great Indian bustard** (godawan), and the **snow leopard** — full or partial legal protection against hunting and trade right across India.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 9, 'html_animation', $lj${"title":"WHO THE SHIELD COVERS","caption":"One by one, India's most threatened animals were brought under legal protection.","html":"<div style=\"background:#f8fafc;padding:20px 14px;border-radius:12px;text-align:center;\">\n  <style>\n    @keyframes geoName { 0%,5%{opacity:0} 22%,100%{opacity:1} }\n    @keyframes geoName2 { 0%,28%{opacity:0} 45%,100%{opacity:1} }\n    @keyframes geoName3 { 0%,51%{opacity:0} 68%,100%{opacity:1} }\n    @keyframes geoName4 { 0%,74%{opacity:0} 90%,100%{opacity:1} }\n    .gn { display:inline-block; margin:4px 6px; padding:5px 11px; border-radius:8px; background:#dcfce7; color:#166534; font:bold 11px sans-serif; }\n    .gn1{animation:geoName 5s infinite} .gn2{animation:geoName2 5s infinite} .gn3{animation:geoName3 5s infinite} .gn4{animation:geoName4 5s infinite}\n  </style>\n  <div style=\"font:bold 11px sans-serif;color:#0f172a;margin-bottom:8px\">PROTECTED UNDER LAW</div>\n  <span class=\"gn gn1\">Tiger</span><span class=\"gn gn2\">One-horned rhino</span><span class=\"gn gn3\">Asiatic lion</span><span class=\"gn gn4\">Snow leopard</span>\n</div>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 10, 'mcq', $lj${"question":"What were the three main thrusts of the Wildlife (Protection) Act, 1972?","options":[{"id":"a","text":"Build zoos, charge entry fees, and fund research.","is_correct":false,"rationale":"None of these is the Act's thrust. It was about banning, protecting, and restricting — not zoos or fees."},{"id":"b","text":"Ban hunting of endangered species, give legal protection to their habitats, and restrict trade in wildlife.","is_correct":true,"rationale":"Exactly — those three, plus an all-India list of protected species, were the heart of the 1972 Act."},{"id":"c","text":"Allow regulated hunting, open trade, and clear forests for farming.","is_correct":false,"rationale":"That's the opposite of the Act, which *banned* hunting and *restricted* trade."},{"id":"d","text":"Hand all forests to private owners.","is_correct":false,"rationale":"The Act strengthened public/legal protection of wildlife and habitats, not private ownership."}],"xp":10}$lj$::jsonb, 10, true),
    (v_lesson, 11, 'tap_to_match', $lj${"prompt":"Match each protected animal to its other name.","left":[{"id":"l1","label":"Kashmir stag"},{"id":"l2","label":"Black buck"},{"id":"l3","label":"Great Indian bustard"},{"id":"l4","label":"A type of crocodile"}],"right":[{"id":"r1","label":"Hangul"},{"id":"r2","label":"Chinkara"},{"id":"r3","label":"Godawan"},{"id":"r4","label":"Gharial"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]}$lj$::jsonb, 10, true),
    (v_lesson, 12, 'exercise', $lj${"instruction":"Find one **national park or wildlife sanctuary** in your state (or the nearest one).\n\nOn paper, note its name and one animal it protects. Then type the park's name and its state below.\n","tool":"pencil","placeholder":"___ in the state of ___ protects the ___."}$lj$::jsonb, 15, true),
    (v_lesson, 13, 'fill_in_the_blank', $lj${"prompt":"Lock in the three thrusts of the 1972 Act.","template":"The 1972 Act protected wildlife by banning {{blank-1}}, giving legal protection to their {{blank-2}}, and restricting {{blank-3}} in wildlife.\n","answers":[{"id":"blank-1","accepted":["hunting","Hunting"]},{"id":"blank-2","accepted":["habitats","Habitats","habitat"]},{"id":"blank-3","accepted":["trade","Trade"]}]}$lj$::jsonb, 10, true),
    (v_lesson, 14, 'reflection', $lj${"prompt":"A law can ban hunting on paper — but a tiger lives far from any courtroom. What do you think it actually takes to make a wildlife law *work* on the ground?\n\nNo right answer.\n","placeholder":"For the law to really work, you'd need..."}$lj$::jsonb, 5, true),
    (v_lesson, 15, 'checkpoint', $lj${"title":"You know how India first put a legal shield around its wildlife.","summary":"The 1972 Wildlife (Protection) Act banned hunting, protected habitats, restricted trade, and named the species to be saved — backed by national parks, sanctuaries, and projects for animals like the rhino and the lion.\n\nBut one of those projects became the most famous wildlife campaign in the world — because one animal had crashed from 55,000 to under 2,000. Next: the story of Project Tiger.\n","xp":0}$lj$::jsonb, 0, true);
  INSERT INTO lessons (course_id, slug, translations, order_index, estimated_minutes, xp_reward, format, is_published)
  INSERT INTO lesson_turns (lesson_id, order_index, turn_type, content, xp_reward, is_required) VALUES
    (v_lesson, 1, 'tutor_message', $lj${"text":"Around the year 1900, India had roughly **55,000 tigers**.\n\nBy 1973, when someone finally counted, just **1,827** were left.\n\nThat's not a decline. That's a collapse. What happened — and why did saving the tiger end up saving the whole forest?\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 2, 'tutor_message', $lj${"text":"The tiger is a **key species** in the faunal web — a predator at the very top.\n\nWhen the authorities took stock in 1973, the scale of the crash was undeniable: from about **55,000** at the turn of the century down to **1,827**.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 3, 'media', $lj${"kind":"image","url":"https://dfdocnhhxrnvblbwwium.supabase.co/storage/v1/object/public/lesson-images/b-class-10-geography-ch02-forest-and-wildlife-resources/c2l2-bengal-tiger.png","caption":"The Bengal tiger — the flagship of Project Tiger, and of India's whole conservation effort.","aspect_ratio":1.7778}$lj$::jsonb, 0, true),
    (v_lesson, 4, 'svg_graphic', $lj${"title":"THE TIGER COLLAPSE","caption":"From about 55,000 tigers in 1900 to just 1,827 by 1973.","svg":"<svg viewBox=\"0 0 360 180\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <line x1=\"40\" y1=\"150\" x2=\"330\" y2=\"150\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <rect x=\"70\" y=\"32\" width=\"70\" height=\"118\" fill=\"#f59e0b\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"105\" y=\"26\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"bold\" fill=\"#92400e\">55,000</text>\n  <text x=\"105\" y=\"165\" text-anchor=\"middle\" font-size=\"9\" fill=\"#475569\">~1900</text>\n  <rect x=\"230\" y=\"142\" width=\"70\" height=\"8\" fill=\"#f59e0b\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"265\" y=\"134\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"bold\" fill=\"#b91c1c\">1,827</text>\n  <text x=\"265\" y=\"165\" text-anchor=\"middle\" font-size=\"9\" fill=\"#475569\">1973</text>\n  <path d=\"M150,40 Q200,30 224,132\" stroke=\"#b91c1c\" stroke-width=\"2\" fill=\"none\" stroke-dasharray=\"5 3\"/>\n  <polygon points=\"224,132 219,120 230,124\" fill=\"#b91c1c\"/>\n</svg>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 5, 'tutor_message', $lj${"text":"What drove the crash? Four forces, all at once:\n\n- **Poaching** for trade\n- **Shrinking habitat** as forests were cleared\n- **Depletion of prey** — fewer deer and boar to hunt\n- a **growing human population** pressing into tiger country\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 6, 'tutor_message', $lj${"text":"The deadliest pull was *trade*.\n\nTiger **skins**, and **bones** used in traditional medicines — especially across many Asian countries — made a tiger worth more dead than alive. And because India and Nepal shelter about **two-thirds** of the world's surviving tigers, they became the prime targets for poachers and illegal traders.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 7, 'tutor_message', $lj${"text":"So in **1973**, India launched **Project Tiger** — one of the most publicised wildlife campaigns the world has seen.\n\nBut here's the clever idea at its heart.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 8, 'tutor_message', $lj${"text":"A tiger needs an enormous, healthy forest — full of prey, water, and cover. Protect *that*, and you automatically protect *everything* living in it.\n\nThe tiger is an **umbrella**: spread protection over the big cat, and its shade shelters the deer, the birds, the insects, the trees — the whole web beneath it.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 9, 'html_animation', $lj${"title":"THE TIGER UMBRELLA","caption":"Protect the tiger's forest, and every species under it is sheltered too.","html":"<div style=\"background:#f8fafc;padding:18px 12px;border-radius:12px;text-align:center;\">\n  <style>\n    @keyframes geoOpen { 0%,10%{transform:scale(0.2);opacity:0} 55%,100%{transform:scale(1);opacity:1} }\n    @keyframes geoUnder { 0%,45%{opacity:0} 70%,100%{opacity:1} }\n    .geo-canopy { transform-origin:center bottom; animation: geoOpen 4.5s ease-out infinite alternate; }\n    .geo-under { animation: geoUnder 4.5s infinite alternate; }\n  </style>\n  <svg viewBox=\"0 0 300 130\" style=\"max-width:320px;width:100%\" font-family=\"sans-serif\">\n    <path class=\"geo-canopy\" d=\"M40,70 A110,70 0 0 1 260,70 Z\" fill=\"#f59e0b\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n    <text x=\"150\" y=\"58\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#7c2d12\" class=\"geo-canopy\">TIGER</text>\n    <g class=\"geo-under\" fill=\"#16a34a\">\n      <circle cx=\"90\" cy=\"100\" r=\"11\"/><circle cx=\"130\" cy=\"104\" r=\"9\"/>\n      <circle cx=\"170\" cy=\"104\" r=\"9\"/><circle cx=\"210\" cy=\"100\" r=\"11\"/>\n    </g>\n    <text x=\"150\" y=\"126\" text-anchor=\"middle\" font-size=\"8\" fill=\"#475569\" class=\"geo-under\">deer, birds, insects, trees — all sheltered</text>\n  </svg>\n</div>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 10, 'tutor_message', $lj${"text":"Project Tiger spread across India in famous reserves: **Corbett** in Uttarakhand, **Sunderbans** in West Bengal, **Bandhavgarh** in Madhya Pradesh, **Sariska** in Rajasthan, **Manas** in Assam, and **Periyar** in Kerala.\n\nAnd conservation kept growing up. It now guards *whole biodiversity*, not a few stars — even **insects**. Notifications under the Wildlife Act (1980, 1986) added butterflies, moths, beetles, even a dragonfly; in **1991**, plants made the protected list for the first time.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 11, 'mcq', $lj${"question":"Why is protecting the tiger described as protecting the whole forest?","options":[{"id":"a","text":"Because tigers plant new trees as they roam.","is_correct":false,"rationale":"Tigers don't plant trees. The reason is about *habitat*, not gardening."},{"id":"b","text":"A tiger needs a large, healthy forest full of prey — so safeguarding its home safeguards every species in it.","is_correct":true,"rationale":"Exactly. The tiger is an 'umbrella' species: protect its habitat and you shelter the whole web beneath it."},{"id":"c","text":"Because the law only protects forests that contain tigers.","is_correct":false,"rationale":"Protection isn't limited to tiger forests. The point is ecological — the tiger's needs cover everyone else's."},{"id":"d","text":"Because tigers eat the animals that damage forests.","is_correct":false,"rationale":"Tempting, but the chapter's logic is about habitat size and health, not pest control."}],"xp":10}$lj$::jsonb, 10, true),
    (v_lesson, 12, 'tap_to_match', $lj${"prompt":"Match each tiger reserve to its state.","left":[{"id":"l1","label":"Corbett"},{"id":"l2","label":"Sunderbans"},{"id":"l3","label":"Bandhavgarh"},{"id":"l4","label":"Periyar"}],"right":[{"id":"r1","label":"Uttarakhand"},{"id":"r2","label":"West Bengal"},{"id":"r3","label":"Madhya Pradesh"},{"id":"r4","label":"Kerala"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]}$lj$::jsonb, 10, true),
    (v_lesson, 13, 'exercise', $lj${"instruction":"Pick one tiger reserve or national park from this lesson (or one you know).\n\nOn a map or on paper, locate it and note its state. Then write one threat from this lesson that Project Tiger had to fight. Type the reserve and the threat below.\n","tool":"pencil","placeholder":"___ is in ___ ; one threat to tigers is ___."}$lj$::jsonb, 15, true),
    (v_lesson, 14, 'fill_in_the_blank', $lj${"prompt":"Lock in the key facts.","template":"Project Tiger was launched in {{blank-1}}, and India and Nepal together shelter about {{blank-2}} of the world's surviving tigers.\n","answers":[{"id":"blank-1","accepted":["1973"]},{"id":"blank-2","accepted":["two-thirds","two thirds","2/3","twothirds"]}]}$lj$::jsonb, 10, true),
    (v_lesson, 15, 'reflection', $lj${"prompt":"A single famous animal pulled an entire forest's worth of life under protection. Is it fair that the unglamorous species got saved only because they happened to live near a tiger? What does that say about how we choose what to protect?\n\nNo right answer.\n","placeholder":"I think choosing a flagship species..."}$lj$::jsonb, 5, true),
    (v_lesson, 16, 'checkpoint', $lj${"title":"You can tell the story of Project Tiger — and the umbrella idea behind it.","summary":"From 55,000 to 1,827, the tiger nearly vanished to poaching, lost habitat, lost prey, and human pressure. Project Tiger (1973) fought back — and by protecting the tiger's forest, it sheltered the whole web, widening over time to cover even insects and plants.\n\nBut forests themselves are sorted and guarded in different ways. Some are India's most strictly protected; some are left to local communities. How exactly are India's forests classified? That's the next lesson.\n","xp":0}$lj$::jsonb, 0, true);
  INSERT INTO lessons (course_id, slug, translations, order_index, estimated_minutes, xp_reward, format, is_published)
  INSERT INTO lesson_turns (lesson_id, order_index, turn_type, content, xp_reward, is_required) VALUES
    (v_lesson, 1, 'tutor_message', $lj${"text":"Not every forest in India is guarded the same way.\n\nSome are the country's crown jewels, strictly protected. Some are watched but a step looser. And some are left largely to the villages that live in them.\n\nThree tiers — and the difference is *how tightly each is guarded*.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 2, 'tutor_message', $lj${"text":"India's forests are vast, and hard to manage, control, and regulate. Much of the forest and wildlife is owned or managed by the **government**, through the Forest Department.\n\nTo handle it, the forest is sorted into **three categories**.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 3, 'tutor_message', $lj${"text":"**1. Reserved Forests.** More than **half** of all forest land. These are the most strictly guarded — and regarded as the *most valuable* for conserving forest and wildlife. The crown jewels.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 4, 'tutor_message', $lj${"text":"**2. Protected Forests.** About **one-third** of forest area, declared by the Forest Department, and protected from *any further depletion*.\n\nGuarded — but a notch below reserved.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 5, 'tutor_message', $lj${"text":"**3. Unclassed Forests.** Everything else: other forests and wastelands belonging to *both government and private individuals and communities*.\n\nThe loosest tier on paper — and, as we'll see, often cared for by the local communities who live there.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 6, 'media', $lj${"kind":"image","url":"https://dfdocnhhxrnvblbwwium.supabase.co/storage/v1/object/public/lesson-images/b-class-10-geography-ch02-forest-and-wildlife-resources/c2l3-dense-forest.png","caption":"A dense, healthy reserved forest stretching to the horizon — the most protected category.","aspect_ratio":1.7778}$lj$::jsonb, 0, true),
    (v_lesson, 7, 'svg_graphic', $lj${"title":"THREE TIERS OF FOREST","caption":"Reserved (over half, strictest) · Protected (about a third) · Unclassed (the rest).","svg":"<svg viewBox=\"0 0 360 150\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <rect x=\"20\" y=\"34\" width=\"166\" height=\"40\" fill=\"#15803d\" stroke=\"#0f172a\" stroke-width=\"1.2\"/>\n  <rect x=\"186\" y=\"34\" width=\"106\" height=\"40\" fill=\"#65a30d\" stroke=\"#0f172a\" stroke-width=\"1.2\"/>\n  <rect x=\"292\" y=\"34\" width=\"48\" height=\"40\" fill=\"#cbd5e1\" stroke=\"#0f172a\" stroke-width=\"1.2\"/>\n  <text x=\"103\" y=\"59\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#ffffff\">Reserved</text>\n  <text x=\"239\" y=\"59\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#ffffff\">Protected</text>\n  <text x=\"316\" y=\"55\" text-anchor=\"middle\" font-size=\"8\" font-weight=\"bold\" fill=\"#0f172a\">Unclas-</text>\n  <text x=\"316\" y=\"65\" text-anchor=\"middle\" font-size=\"8\" font-weight=\"bold\" fill=\"#0f172a\">sed</text>\n  <text x=\"103\" y=\"92\" text-anchor=\"middle\" font-size=\"8\" fill=\"#475569\">&gt; half · most valuable</text>\n  <text x=\"239\" y=\"92\" text-anchor=\"middle\" font-size=\"8\" fill=\"#475569\">~ one-third</text>\n  <text x=\"316\" y=\"92\" text-anchor=\"middle\" font-size=\"8\" fill=\"#475569\">the rest</text>\n  <text x=\"20\" y=\"120\" font-size=\"8\" fill=\"#166534\">◄ strictly guarded</text>\n  <text x=\"340\" y=\"120\" text-anchor=\"end\" font-size=\"8\" fill=\"#64748b\">loosely guarded ►</text>\n</svg>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 8, 'tutor_message', $lj${"text":"Reserved and protected forests together are called **permanent forest estates** — kept permanently for producing **timber** and for **protection**.\n\n**Madhya Pradesh** has the largest area under permanent forests: a remarkable **75%** of its total forest.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 9, 'tutor_message', $lj${"text":"The pattern shifts across India:\n\n- Large *reserved* forests: Jammu & Kashmir, Andhra Pradesh, Uttarakhand, Kerala, Tamil Nadu, West Bengal, Maharashtra.\n- Mostly *protected*: Bihar, Haryana, Punjab, Himachal Pradesh, Odisha, Rajasthan.\n- Very high *unclassed* (managed by local communities): all the North-eastern states and parts of Gujarat.\n","persona_id":"nova"}$lj$::jsonb, 0, true),
    (v_lesson, 10, 'html_animation', $lj${"title":"GUARDED, TIER BY TIER","caption":"From the strictly reserved down to the community-held unclassed forests.","html":"<div style=\"background:#f8fafc;padding:18px 14px;border-radius:12px;\">\n  <style>\n    @keyframes geoTier1 { 0%,5%{opacity:0;transform:translateX(-12px)} 25%,100%{opacity:1;transform:none} }\n    @keyframes geoTier2 { 0%,30%{opacity:0;transform:translateX(-12px)} 50%,100%{opacity:1;transform:none} }\n    @keyframes geoTier3 { 0%,55%{opacity:0;transform:translateX(-12px)} 75%,100%{opacity:1;transform:none} }\n    .gt1{animation:geoTier1 5s infinite} .gt2{animation:geoTier2 5s infinite} .gt3{animation:geoTier3 5s infinite}\n    .geo-row{display:flex;align-items:center;margin:6px 0;font:bold 11px sans-serif;color:#fff;border-radius:6px;padding:7px 12px}\n  </style>\n  <div class=\"geo-row gt1\" style=\"background:#15803d\">Reserved — strictest, most valuable</div>\n  <div class=\"geo-row gt2\" style=\"background:#65a30d\">Protected — no further depletion</div>\n  <div class=\"geo-row gt3\" style=\"background:#94a3b8\">Unclassed — govt, private, communities</div>\n</div>\n"}$lj$::jsonb, 0, true),
    (v_lesson, 11, 'mcq', $lj${"question":"Which forest category makes up over half the forest land and is regarded as the most valuable for conservation?","options":[{"id":"a","text":"Protected forests","is_correct":false,"rationale":"Protected forests are about a third of forest area and a notch below reserved in protection."},{"id":"b","text":"Reserved forests","is_correct":true,"rationale":"Right — over half of forest land, the most strictly guarded, and the most valuable for conserving forest and wildlife."},{"id":"c","text":"Unclassed forests","is_correct":false,"rationale":"Unclassed forests are the rest — other forests and wastelands held by government, private owners, and communities."},{"id":"d","text":"Permanent forest estates","is_correct":false,"rationale":"That's the combined name for reserved + protected forests, not a separate, larger category."}],"xp":10}$lj$::jsonb, 10, true),
    (v_lesson, 12, 'tap_to_match', $lj${"prompt":"Match each forest category to its description.","left":[{"id":"l1","label":"Reserved forests"},{"id":"l2","label":"Protected forests"},{"id":"l3","label":"Unclassed forests"}],"right":[{"id":"r1","label":"Most valuable for conserving forest and wildlife"},{"id":"r2","label":"Protected from any further depletion"},{"id":"r3","label":"Other forests and wastelands of govt, private owners, and communities"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"]]}$lj$::jsonb, 10, true),
    (v_lesson, 13, 'exercise', $lj${"instruction":"Think about your own state. Based on this lesson, which category do you think most of its forest falls under — reserved, protected, or largely unclassed (community-managed)?\n\nOn paper, make your guess and give one reason. Type your state and your guess below.\n","tool":"pencil","placeholder":"In ___ , most forest is probably ___ because..."}$lj$::jsonb, 15, true),
    (v_lesson, 14, 'fill_in_the_blank', $lj${"prompt":"Lock in the structure.","template":"Reserved forests make up over {{blank-1}} of forest land, and reserved plus protected forests together form {{blank-2}} forest estates.\n","answers":[{"id":"blank-1","accepted":["half","Half","50%"]},{"id":"blank-2","accepted":["permanent","Permanent"]}]}$lj$::jsonb, 10, true),
    (v_lesson, 15, 'reflection', $lj${"prompt":"The \"loosest\" tier — unclassed forest — is often the one local communities care for directly. Do you think a forest is safer guarded by a distant government rule, or by the people who live right beside it?\n\nNo right answer.\n","placeholder":"I think a forest is safer when..."}$lj$::jsonb, 5, true),
    (v_lesson, 16, 'checkpoint', $lj${"title":"You can classify India's forests into three tiers of protection.","summary":"Reserved (over half, strictest, most valuable), protected (about a third, no further depletion), and unclassed (the rest, held by government, private owners, and communities) — with reserved and protected together forming the permanent forest estates.\n\nNotice that last tier kept pointing at *communities*. And that's the quiet truth this whole chapter has been building toward: some of India's best conservation never came from a government at all — it came from villagers. That's the final course.\n","xp":0}$lj$::jsonb, 0, true);
