DO $deploy$
DECLARE v_lesson uuid;
BEGIN

  -- biodiversity-and-the-web-of-life/we-are-one-strand-in-the-web
  VALUES ((SELECT id FROM courses WHERE slug = 'biodiversity-and-the-web-of-life'), 'we-are-one-strand-in-the-web', $lj${"en":{"title":"We Are One Strand in the Web","subtitle":"Why your every breath is a favour from other living things"},"hinglish":{"title":"Hum Web ka Ek Dhaaga Hain","subtitle":"Tumhari har saans doosre jeevon ka ehsaan kyun hai","turns":[{"order_index":1,"turn_type":"tutor_message","content":{"text":"Yeh try karo: aaj tumne koi ek aisa kaam batao jo kisi doosre jeev pe depend nahi karta.\n\nJo hawa tumne li? Paudhon ne banayi. Jo paani piya? Jeevon ke ek poore web ne saaf kiya. Tumhara breakfast? Mitti, microbes, aur dhoop ne saath milke banaya.\n\nHum kabhi gaur nahi karte. Aaj, gaur karte hain.\n","persona_id":"nova"},"xp_reward":0},{"order_index":2,"turn_type":"tutor_message","content":{"text":"Hum is planet ko *millions* doosre jeevon ke saath share karte hain — **micro-organisms** aur **bacteria** se lekar, **lichens**, **banyan** ke ped, **haathi**, aur **blue whales** tak.\n\nYeh sab milke banate hain planet ki immense **biodiversity** — jeevan ki sheer variety.\n","persona_id":"nova"},"xp_reward":0},{"order_index":3,"turn_type":"tutor_message","content":{"text":"Ab sabse vinamr karne waali baat.\n\nHum insaan, *har* doosre jeev ke saath, ek hi **web** banate hain — ek complex *ecological system*. Hum uske upar baith ke neeche nahi dekh rahe.\n\nHum uska **ek dhaaga** hain. Aur kisi bhi dhaage ki tarah, hum jeene ke liye poore web pe depend karte hain.\n","persona_id":"nova"},"xp_reward":0},{"order_index":4,"turn_type":"media","content":{"kind":"image","url":"https://dfdocnhhxrnvblbwwium.supabase.co/storage/v1/object/public/lesson-images/b-class-10-geography-ch02-forest-and-wildlife-resources/c1l1-biodiverse-forest.png","caption":"Ek hara-bhara, biodiverse Indian jungle — anginat species ek hi jeevit jaal mein.","aspect_ratio":1.7778},"xp_reward":0},{"order_index":5,"turn_type":"svg_graphic","content":{"title":"JEEVAN KA WEB","caption":"Sun, forests, microbes, animals, humans — sab ek doosre se gunde. Tum ek node ho, top nahi.","svg":"<svg viewBox=\"0 0 360 200\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <line x1=\"180\" y1=\"30\" x2=\"70\" y2=\"92\" stroke=\"#cbd5e1\" stroke-width=\"1.5\"/>\n  <line x1=\"180\" y1=\"30\" x2=\"290\" y2=\"92\" stroke=\"#cbd5e1\" stroke-width=\"1.5\"/>\n  <line x1=\"70\" y1=\"96\" x2=\"290\" y2=\"96\" stroke=\"#cbd5e1\" stroke-width=\"1.5\"/>\n  <line x1=\"70\" y1=\"96\" x2=\"120\" y2=\"166\" stroke=\"#cbd5e1\" stroke-width=\"1.5\"/>\n  <line x1=\"70\" y1=\"96\" x2=\"250\" y2=\"166\" stroke=\"#cbd5e1\" stroke-width=\"1.5\"/>\n  <line x1=\"290\" y1=\"96\" x2=\"120\" y2=\"166\" stroke=\"#cbd5e1\" stroke-width=\"1.5\"/>\n  <line x1=\"290\" y1=\"96\" x2=\"250\" y2=\"166\" stroke=\"#cbd5e1\" stroke-width=\"1.5\"/>\n  <line x1=\"120\" y1=\"166\" x2=\"250\" y2=\"166\" stroke=\"#cbd5e1\" stroke-width=\"1.5\"/>\n  <circle cx=\"180\" cy=\"28\" r=\"17\" fill=\"#fde68a\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"180\" y=\"32\" text-anchor=\"middle\" font-size=\"8\" fill=\"#92400e\">sun</text>\n  <circle cx=\"70\" cy=\"96\" r=\"24\" fill=\"#bbf7d0\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"70\" y=\"93\" text-anchor=\"middle\" font-size=\"8\" fill=\"#166534\">forests,</text>\n  <text x=\"70\" y=\"103\" text-anchor=\"middle\" font-size=\"8\" fill=\"#166534\">plants</text>\n  <circle cx=\"290\" cy=\"96\" r=\"24\" fill=\"#99f6e4\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"290\" y=\"93\" text-anchor=\"middle\" font-size=\"8\" fill=\"#115e59\">microbes,</text>\n  <text x=\"290\" y=\"103\" text-anchor=\"middle\" font-size=\"8\" fill=\"#115e59\">bacteria</text>\n  <circle cx=\"120\" cy=\"168\" r=\"22\" fill=\"#fed7aa\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"120\" y=\"171\" text-anchor=\"middle\" font-size=\"8\" fill=\"#9a3412\">animals</text>\n  <circle cx=\"250\" cy=\"168\" r=\"22\" fill=\"#bfdbfe\" stroke=\"#0f172a\" stroke-width=\"2.5\"/>\n  <text x=\"250\" y=\"165\" text-anchor=\"middle\" font-size=\"8\" font-weight=\"bold\" fill=\"#1e3a8a\">humans</text>\n  <text x=\"250\" y=\"176\" text-anchor=\"middle\" font-size=\"7\" fill=\"#1e3a8a\">(you)</text>\n</svg>\n"},"xp_reward":0},{"order_index":6,"turn_type":"tutor_message","content":{"text":"Hum web pe kitna *literally* depend karte hain? Poori tarah.\n\nPaudhe, jaanwar, aur micro-organisms un cheezon ko **dobaara banate** hain jinke bina hum nahi jee sakte:\n\n- jo **hawa** hum saans mein lete hain\n- jo **paani** hum peete hain\n- jo **mitti** hamara khaana ugaati hai\n\nInhe hata do, aur hum zyaada der nahi tikte.\n","persona_id":"nova"},"xp_reward":0},{"order_index":7,"turn_type":"tutor_message","content":{"text":"Aur poore web ke *base* pe baithte hain **forests**.\n\nYeh **primary producers** hain — woh jeev jo dhoop ko khaane mein badalte hain. Baaki sab woh khaana khaate hain, seedhe ya ghuma ke. Forest chupchaap poore web ko khilaata hai.\n","persona_id":"nova"},"xp_reward":0},{"order_index":8,"turn_type":"tutor_message","content":{"text":"Toh **biodiversity** hai kya, theek-theek?\n\nYeh wildlife aur cultivated species ki immense richness hai — *form aur function mein diverse, par interdependencies ke ek network se aapas mein kasi hui.*\n\nUs aakhri shabd ko pakdo: **interdependencies**. Web mein, koi cheez akeli nahi khadi.\n","persona_id":"nova"},"xp_reward":0},{"order_index":9,"turn_type":"html_animation","content":{"title":"EK DHAAGA KHEENCHO","caption":"Web ka ek dhaaga kheencho aur poora web kaanp uthta hai — humare tak.","html":"<div style=\"background:#f8fafc;padding:18px 12px;border-radius:12px;text-align:center;\">\n  <style>\n    @keyframes geoShake { 0%,100%{transform:translate(0,0)} 25%{transform:translate(-3px,2px)} 50%{transform:translate(3px,-2px)} 75%{transform:translate(-2px,-2px)} }\n    @keyframes geoPulse { 0%,100%{fill:#fca5a5} 50%{fill:#dc2626} }\n    .geo-web { animation: geoShake 1.6s ease-in-out infinite; transform-origin:center; }\n    .geo-pulled { animation: geoPulse 1.6s ease-in-out infinite; }\n  </style>\n  <svg viewBox=\"0 0 300 150\" style=\"max-width:320px;width:100%\" font-family=\"sans-serif\">\n    <g class=\"geo-web\">\n      <line x1=\"150\" y1=\"30\" x2=\"60\" y2=\"90\" stroke=\"#94a3b8\" stroke-width=\"1.5\"/>\n      <line x1=\"150\" y1=\"30\" x2=\"240\" y2=\"90\" stroke=\"#94a3b8\" stroke-width=\"1.5\"/>\n      <line x1=\"60\" y1=\"90\" x2=\"240\" y2=\"90\" stroke=\"#94a3b8\" stroke-width=\"1.5\"/>\n      <line x1=\"60\" y1=\"90\" x2=\"150\" y2=\"125\" stroke=\"#94a3b8\" stroke-width=\"1.5\"/>\n      <line x1=\"240\" y1=\"90\" x2=\"150\" y2=\"125\" stroke=\"#94a3b8\" stroke-width=\"1.5\"/>\n      <circle cx=\"150\" cy=\"30\" r=\"10\" fill=\"#86efac\" stroke=\"#0f172a\" stroke-width=\"1\"/>\n      <circle cx=\"60\" cy=\"90\" r=\"10\" fill=\"#93c5fd\" stroke=\"#0f172a\" stroke-width=\"1\"/>\n      <circle cx=\"240\" cy=\"90\" r=\"10\" fill=\"#fdba74\" stroke=\"#0f172a\" stroke-width=\"1\"/>\n      <circle cx=\"150\" cy=\"125\" r=\"11\" class=\"geo-pulled\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n    </g>\n    <text x=\"150\" y=\"147\" text-anchor=\"middle\" font-size=\"8\" fill=\"#991b1b\">one strand pulled — the whole web shakes</text>\n  </svg>\n</div>\n"},"xp_reward":0},{"order_index":10,"turn_type":"tutor_message","content":{"text":"*Agar ek dhaaga toot jaaye toh kya tootega?*\n\nBees nikaal do, ya mitti ke bacteria, ya ek poora forest — aur jhatka web ke *aar-paar* daudta hai — dhaagon ke upar, humare tak.\n\nIsiliye koi extinction kabhi sach mein \"chhoti\" nahi hoti. Web har nuksaan mehsoos karta hai.\n","persona_id":"nova"},"xp_reward":0},{"order_index":11,"turn_type":"mcq","content":{"question":"Chapter forests ko ecological system ka 'primary producers' kyun kehta hai?","options":[{"id":"a","text":"Kyunki woh insaani use ke liye sabse zyaada timber paida karte hain.","is_correct":false,"rationale":"Timber forests ka ek human *use* hai, ecology mein 'primary producer' kehlaane ki wajah nahi."},{"id":"b","text":"Kyunki woh dhoop ko khaane mein badalte hain jis pe baaki har jeev depend karta hai, seedhe ya ghuma ke.","is_correct":true,"rationale":"Bilkul. Primary producers web ke base pe khaana banate hain — baaki sab aage chal ke usi pe palte hain."},{"id":"c","text":"Kyunki insaano ne unme se zyaadatar pehle lagaye.","is_correct":false,"rationale":"Forests zyaadatar insaan-made nahi hote, aur yeh 'primary producer' ke matlab se alag baat hai."},{"id":"d","text":"Kyunki woh Earth ke sabse puraane jeev hain.","is_correct":false,"rationale":"Umar point nahi hai. 'Primary producer' ka matlab hai food web ke base pe dhoop se khaana banana."}],"xp":10},"xp_reward":10},{"order_index":12,"turn_type":"tap_to_match","content":{"prompt":"Web ke har hisse ko uske role se match karo.","left":[{"id":"l1","label":"Forests aur plants"},{"id":"l2","label":"Micro-organisms aur bacteria"},{"id":"l3","label":"Poora web milke"},{"id":"l4","label":"Insaan"}],"right":[{"id":"r1","label":"Primary producers — dhoop ko khaane mein badalte hain"},{"id":"r2","label":"Saaf mitti, hawa, aur paani dobaara banane mein madad"},{"id":"r3","label":"Biodiversity — interdependencies se judi variety"},{"id":"r4","label":"Ek depend karne waala dhaaga, top nahi"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]},"xp_reward":10},{"order_index":13,"turn_type":"exercise","content":{"instruction":"Pichhle ek ghante mein tumne jo teen cheezein use kii — khaana, paani, paper, koi lakdi ki cheez, ya kamre ki hawa.\n\nPaper pe har ek ko web ke us *jeev* tak trace karo jisne use mumkin banaya. Phir neeche unme se ek aur uska living source type karo.\n","tool":"pencil","placeholder":"Jo ___ maine use kiya woh web ke ___ se aaya."},"xp_reward":15},{"order_index":14,"turn_type":"fill_in_the_blank","content":{"prompt":"Do key ideas yaad kar lo.","template":"Forests ecological system ke {{blank-1}} producers hain, aur biodiversity {{blank-2}} ke ek network se judi rehti hai.\n","answers":[{"id":"blank-1","accepted":["primary","Primary"]},{"id":"blank-2","accepted":["interdependencies","interdependence","Interdependencies"]}]},"xp_reward":10},{"order_index":15,"turn_type":"reflection","content":{"prompt":"\"Hum web ke ek dhaage hain, top nahi.\" Kya yeh tumhari nazar mein nature mein apni jagah badalta hai — ya thoda uncomfortable lagta hai? Imaandaar raho.\n\nKoi sahi jawaab nahi.\n","placeholder":"Khud ko ek dhaaga samajh kar..."},"xp_reward":5},{"order_index":16,"turn_type":"checkpoint","content":{"title":"Ab tum khud ko web of life ke andar dekhte ho, uske upar nahi.","summary":"Planet biodiversity pe chalta hai — millions species ka ek web, interdependencies se bandha, jisme forests primary producers ban ke sabko khilaate hain. Hum ek dhaaga hain, baaki sab pe poori tarah depend.\n\nAur baat yeh hai: India us web ka ek sabse *rich* hissa rakhta hai. Yeh ek desh kitni living wealth uthaaye hue hai — aur woh khatre mein kyun hai? Yahi agli lesson hai.\n","xp":0},"xp_reward":0}]}}$lj$::jsonb, 1, 11, 100, 'ai_chat', true)
  ON CONFLICT (course_id, slug) DO UPDATE SET
    translations = excluded.translations,
    order_index = excluded.order_index,
    estimated_minutes = excluded.estimated_minutes,
    xp_reward = excluded.xp_reward,
