  RETURNING id INTO v_lesson;
  DELETE FROM lesson_turns WHERE lesson_id = v_lesson;

  -- biodiversity-and-the-web-of-life/indias-living-wealth
  VALUES ((SELECT id FROM courses WHERE slug = 'biodiversity-and-the-web-of-life'), 'indias-living-wealth', $lj${"en":{"title":"India's Living Wealth","subtitle":"A library of life where most of the books are still unread"},"hinglish":{"title":"India ki Living Wealth","subtitle":"Jeevan ki ek library jahan zyaadatar kitaabein abhi padhi hi nahi gayin","turns":[{"order_index":1,"turn_type":"tutor_message","content":{"text":"India ki wildlife ko ek vishaal **library** ki tarah socho.\n\nAb socho ki humne usme se sirf *ek tihaai* kitaabein padhi hain. Baaki abhi bhi shelves pe hain — bina catalogue, kuch kabhi kholi hi nahi gayi.\n\nYeh metaphor ka khinchaav nahi. Yeh lagbhag sach hai.\n","persona_id":"nova"},"xp_reward":0},{"order_index":2,"turn_type":"tutor_message","content":{"text":"India biological diversity ke maamle mein duniya ke **sabse rich deshon** mein se ek hai — **flora** (paudhon ka jeevan) aur **fauna** (jaanwaron ka jeevan) ka ek vishaal khazaana.\n\nHimalaya se lekar coasts tak aur registan tak, planet pe kam jagahein itni variety samete hain.\n","persona_id":"nova"},"xp_reward":0},{"order_index":3,"turn_type":"tutor_message","content":{"text":"Ab sabse hairaan karne waali baat.\n\nJo species humne sach mein *naam diye aur padhe* hain, woh shayad jo asal mein yahan hai uska ek chhota hissa hai. Scientists ka maanna hai ki asli number **do ya teen guna** zyaada ho sakta hai — abhi bhi discover hone ka wait karta hua.\n\nIndia ki living library ka zyaadatar hissa, literally, *unread* hai.\n","persona_id":"nova"},"xp_reward":0},{"order_index":4,"turn_type":"media","content":{"kind":"image","url":"https://dfdocnhhxrnvblbwwium.supabase.co/storage/v1/object/public/lesson-images/b-class-10-geography-ch02-forest-and-wildlife-resources/c1l2-india-wildlife.png","caption":"India ki jeevit daulat: baagh, haathi, mor, hiran, hornbill — uski biodiversity ka ek chhota hissa.","aspect_ratio":1.7778},"xp_reward":0},{"order_index":5,"turn_type":"svg_graphic","content":{"title":"INDIA KI LIBRARY OF LIFE","caption":"Jo species hum jaante hain (baayein) woh shayad sirf ek tihaai — baaki abhi bhi undiscovered.","svg":"<svg viewBox=\"0 0 360 160\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <rect x=\"14\" y=\"20\" width=\"332\" height=\"104\" rx=\"4\" fill=\"#f8fafc\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <rect x=\"26\" y=\"32\" width=\"14\" height=\"80\" fill=\"#16a34a\"/>\n  <rect x=\"44\" y=\"32\" width=\"14\" height=\"80\" fill=\"#0891b2\"/>\n  <rect x=\"62\" y=\"32\" width=\"14\" height=\"80\" fill=\"#ca8a04\"/>\n  <rect x=\"80\" y=\"32\" width=\"14\" height=\"80\" fill=\"#9333ea\"/>\n  <rect x=\"98\" y=\"32\" width=\"14\" height=\"80\" fill=\"#dc2626\"/>\n  <line x1=\"120\" y1=\"24\" x2=\"120\" y2=\"120\" stroke=\"#94a3b8\" stroke-width=\"1.5\" stroke-dasharray=\"4 3\"/>\n  <rect x=\"132\" y=\"40\" width=\"12\" height=\"72\" fill=\"#e2e8f0\" stroke=\"#cbd5e1\"/>\n  <rect x=\"150\" y=\"40\" width=\"12\" height=\"72\" fill=\"#e2e8f0\" stroke=\"#cbd5e1\"/>\n  <rect x=\"168\" y=\"40\" width=\"12\" height=\"72\" fill=\"#e2e8f0\" stroke=\"#cbd5e1\"/>\n  <rect x=\"186\" y=\"40\" width=\"12\" height=\"72\" fill=\"#e2e8f0\" stroke=\"#cbd5e1\"/>\n  <rect x=\"204\" y=\"40\" width=\"12\" height=\"72\" fill=\"#e2e8f0\" stroke=\"#cbd5e1\"/>\n  <rect x=\"222\" y=\"40\" width=\"12\" height=\"72\" fill=\"#e2e8f0\" stroke=\"#cbd5e1\"/>\n  <rect x=\"240\" y=\"40\" width=\"12\" height=\"72\" fill=\"#e2e8f0\" stroke=\"#cbd5e1\"/>\n  <rect x=\"258\" y=\"40\" width=\"12\" height=\"72\" fill=\"#e2e8f0\" stroke=\"#cbd5e1\"/>\n  <rect x=\"276\" y=\"40\" width=\"12\" height=\"72\" fill=\"#e2e8f0\" stroke=\"#cbd5e1\"/>\n  <rect x=\"294\" y=\"40\" width=\"12\" height=\"72\" fill=\"#e2e8f0\" stroke=\"#cbd5e1\"/>\n  <text x=\"300\" y=\"80\" text-anchor=\"middle\" font-size=\"22\" fill=\"#94a3b8\">?</text>\n  <text x=\"68\" y=\"140\" text-anchor=\"middle\" font-size=\"8\" fill=\"#166534\">known species (~1/3)</text>\n  <text x=\"225\" y=\"140\" text-anchor=\"middle\" font-size=\"8\" fill=\"#64748b\">still to be discovered (~2/3)</text>\n</svg>\n"},"xp_reward":0},{"order_index":6,"turn_type":"tutor_message","content":{"text":"Aur yeh wealth kisi door ke jungle mein nahi hai. Yeh tumhare *charon taraf rozmarra zindagi* mein buni hui hai — plate ka khaana, jo dawaiyan tum lete ho, ghar ki lakdi, tyohaar, geet.\n\nHum isse itne ghire hue hain ki use *granted maan lete hain* — hawa ki tarah.\n","persona_id":"nova"},"xp_reward":0},{"order_index":7,"turn_type":"tutor_message","content":{"text":"India bhar mein, folk songs aur kahaniyan logon aur nature ke beech ek *harmonious* rishte ka jashn manaati hain.\n\nEk Lepcha folk song apni dhun *\"jharno, nadiyon, pahaadon, jungalon, keedon aur jaanwaron se\"* ikattha karti hai. In paramparaon mein nature scenery nahi hai — woh parivaar hai.\n","persona_id":"nova"},"xp_reward":0},{"order_index":8,"turn_type":"tutor_message","content":{"text":"Par haal hi mein, yeh living wealth **bade stress** mein hai.\n\nMukhya wajah sunne mein bhaari hai: hamari apni environment ke prati *insensitivity* (besamajhi). Hum jo chaahein lete hain aur us web ko bhool jaate hain jo keemat chukata hai.\n\n*Agar hum ise ignore karte rahe toh kya tootega?* Wahi library jise hum mushkil se padhna shuru kar paaye.\n","persona_id":"nova"},"xp_reward":0},{"order_index":9,"turn_type":"html_animation","content":{"title":"GRANTED MAANA, STRESS MEIN","caption":"Jis variety ko hum ignore karte hain woh chupchaap kho rahi hai — patte murjhaate hain, rang udte hain.","html":"<div style=\"background:#f8fafc;padding:20px 12px;border-radius:12px;text-align:center;\">\n  <style>\n    @keyframes geoWilt { 0%,20%{fill:#16a34a;opacity:1} 80%,100%{fill:#a1887f;opacity:0.5} }\n    .geo-leaf { animation: geoWilt 4s ease-in-out infinite alternate; }\n  </style>\n  <svg viewBox=\"0 0 300 90\" style=\"max-width:320px;width:100%\" font-family=\"sans-serif\">\n    <g class=\"geo-leaf\">\n      <ellipse cx=\"50\" cy=\"45\" rx=\"13\" ry=\"22\"/>\n      <ellipse cx=\"110\" cy=\"45\" rx=\"13\" ry=\"22\"/>\n      <ellipse cx=\"170\" cy=\"45\" rx=\"13\" ry=\"22\"/>\n      <ellipse cx=\"230\" cy=\"45\" rx=\"13\" ry=\"22\"/>\n    </g>\n  </svg>\n</div>\n"},"xp_reward":0},{"order_index":10,"turn_type":"mcq","content":{"question":"Jab scientists kehte hain ki India ki biodiversity jo hum jaante hain uski 'do ya teen guna' ho sakti hai, unka kya matlab hai?","options":[{"id":"a","text":"India ki wildlife har saal do-teen guna badi ho rahi hai.","is_correct":false,"rationale":"Yeh populations ke *badhne* ke baare mein nahi. Yeh us baare mein hai ki kitni species hain jinhe humne abhi pehchaana nahi."},{"id":"b","text":"Yahan shayad usse kahin zyaada species maujood hain jitni ab tak discover aur naam di gayi hain.","is_correct":true,"rationale":"Sahi — jo species hum jaante hain woh shayad ek chhota hissa hai; asli number do ya teen guna ho sakta hai, abhi bhi undiscovered."},{"id":"c","text":"Indian species kahin aur ki species se do-teen guna badi hoti hain.","is_correct":false,"rationale":"Size se koi lena-dena nahi. Yeh undiscovered species ki *sankhya* ke baare mein hai."},{"id":"d","text":"Har saal do-teen species extinct ho jaati hain.","is_correct":false,"rationale":"Woh ek alag (dukhad) baat hai. 'Do ya teen guna' figure undiscovered diversity ke baare mein hai."}],"xp":10},"xp_reward":10},{"order_index":11,"turn_type":"tap_to_match","content":{"prompt":"Har term ko uske matlab se match karo.","left":[{"id":"l1","label":"Flora"},{"id":"l2","label":"Fauna"},{"id":"l3","label":"'Do ya teen guna'"},{"id":"l4","label":"Environment ke prati insensitivity"}],"right":[{"id":"r1","label":"Paudhon ka jeevan"},{"id":"r2","label":"Jaanwaron ka jeevan"},{"id":"r3","label":"Species jo abhi discover honi hain"},{"id":"r4","label":"Biodiversity ke stress mein hone ki mukhya wajah"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]},"xp_reward":10},{"order_index":12,"turn_type":"exercise","content":{"instruction":"Apne region se koi ek **kahani, geet, tyohaar, ya rivaaj** dhundo jo logon aur nature ke beech aadar bhara ya harmonious rishta dikhata ho (ek pavitra ped, ek surakshit jaanwar, ek fasal ka tyohaar, ek lok-katha).\n\nPaper pe use likho. Phir neeche uska naam aur woh paudha ya jaanwar type karo jise woh maan deta hai.\n","tool":"pencil","placeholder":"Mere region mein, ___ ___ ko maan deta hai."},"xp_reward":15},{"order_index":13,"turn_type":"fill_in_the_blank","content":{"prompt":"Terms yaad kar lo.","template":"India duniya mein {{blank-1}} (paudhon ka jeevan) aur {{blank-2}} (jaanwaron ka jeevan) mein sabse rich mein se hai.\n","answers":[{"id":"blank-1","accepted":["flora","Flora"]},{"id":"blank-2","accepted":["fauna","Fauna"]}]},"xp_reward":10},{"order_index":14,"turn_type":"reflection","content":{"prompt":"India ki zyaadatar species abhi bhi undiscovered hain — phir bhi kayi shayad humare unhe jaanne se pehle hi khatre mein hon. Yeh sochna kaisa lagta hai ki koi species kisi ke use naam dene se pehle hi gayab ho sakti hai?\n\nKoi sahi jawaab nahi.\n","placeholder":"Yeh khayal ki..."},"xp_reward":5},{"order_index":15,"turn_type":"checkpoint","content":{"title":"Tum samajhte ho India kitni living wealth rakhta hai — aur woh khatre mein hai.","summary":"India planet ki ek sabse rich library of life rakhta hai — flora aur fauna jo hamare khaane, aastha, aur geeton mein buni hai, jaani hui se kahin zyaada species abhi bhi undiscovered. Aur woh hamari apni laaparwaahi se asli stress mein hai.\n\nJo seedha sawaal yeh course laata hai: *kyun* exactly humein effort aur paisa kharch karke ise bachana chahiye? Agar biodiversity chali jaaye toh hum asal mein kya khote hain? Yahi agli lesson hai.\n","xp":0},"xp_reward":0}]}}$lj$::jsonb, 2, 11, 100, 'ai_chat', true)
