  -- biodiversity-and-the-web-of-life/why-conservation-matters
  VALUES ((SELECT id FROM courses WHERE slug = 'biodiversity-and-the-web-of-life'), 'why-conservation-matters', $lj${"en":{"title":"Why Conservation Matters","subtitle":"The honest, self-interested reasons to save a species you'll never meet"},"hinglish":{"title":"Conservation Kyun Zaroori Hai","subtitle":"Ek aisi species ko bachane ki imaandaar, swaarthi wajahein jise tum kabhi miloge nahi","turns":[{"order_index":1,"turn_type":"tutor_message","content":{"text":"Khulke poochne laayak ek sawaal: ek aise mendhak ko bachane pe paisa kyun kharch karein jise tum kabhi dekhoge bhi nahi?\n\nImaandaar jawaab *tumhare* baare mein nikalta hai, mendhak ke nahi. Conservation jaanwaron ke liye daan nahi hai. Dikhaata hoon kyun.\n","persona_id":"nova"},"xp_reward":0},{"order_index":2,"turn_type":"tutor_message","content":{"text":"Pehle, urgency. Wildlife populations aur forests **tezi se ghat** rahe hain — isiliye conservation *zaroori* ho gaya hai.\n\nPar \"nature bachao\" tab tak ek slogan hai jab tak tum *kyun* concrete terms mein na keh sako. Teen thos wajahein hain. Koi bhi cuteness ke baare mein nahi.\n","persona_id":"nova"},"xp_reward":0},{"order_index":3,"turn_type":"tutor_message","content":{"text":"**Wajah 1 — hamare life-support systems.**\n\nConservation us ecological diversity ko bachata hai jo hamari **hawa**, **paani**, aur **mitti** ko chalti rakhti hai. Web woh machinery hai jo planet ko rehne laayak banati hai. Use todo, aur jo machine tumhari hawa aur paani saaf karti hai woh bhi toot jaati hai.\n","persona_id":"nova"},"xp_reward":0},{"order_index":4,"turn_type":"svg_graphic","content":{"title":"BIODIVERSITY KYA SAMBHAALTI HAI","caption":"Saaf hawa, paani, mitti, aur jo khaana hum ugate hain — sab biodiversity pe, uski neenv pe tike hain.","svg":"<svg viewBox=\"0 0 360 170\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <rect x=\"20\" y=\"44\" width=\"60\" height=\"78\" rx=\"4\" fill=\"#dbeafe\" stroke=\"#0f172a\" stroke-width=\"1.2\"/>\n  <text x=\"50\" y=\"88\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#1e3a8a\">AIR</text>\n  <rect x=\"106\" y=\"44\" width=\"60\" height=\"78\" rx=\"4\" fill=\"#cffafe\" stroke=\"#0f172a\" stroke-width=\"1.2\"/>\n  <text x=\"136\" y=\"88\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#0e7490\">WATER</text>\n  <rect x=\"192\" y=\"44\" width=\"60\" height=\"78\" rx=\"4\" fill=\"#fde68a\" stroke=\"#0f172a\" stroke-width=\"1.2\"/>\n  <text x=\"222\" y=\"88\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#92400e\">SOIL</text>\n  <rect x=\"278\" y=\"44\" width=\"62\" height=\"78\" rx=\"4\" fill=\"#dcfce7\" stroke=\"#0f172a\" stroke-width=\"1.2\"/>\n  <text x=\"309\" y=\"84\" text-anchor=\"middle\" font-size=\"10\" font-weight=\"bold\" fill=\"#166534\">FOOD</text>\n  <text x=\"309\" y=\"98\" text-anchor=\"middle\" font-size=\"7\" fill=\"#166534\">+ crops</text>\n  <rect x=\"20\" y=\"130\" width=\"320\" height=\"28\" rx=\"4\" fill=\"#16a34a\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"180\" y=\"148\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"bold\" fill=\"#ffffff\">BIODIVERSITY</text>\n</svg>\n"},"xp_reward":0},{"order_index":5,"turn_type":"tutor_message","content":{"text":"**Wajah 2 — genetic diversity: future ka seed bank.**\n\nConservation paudhon aur jaanwaron ki genetic variety bachata hai — *behtar growth aur breeding* ka kaccha maal. Kisi crop ka har wild rishtedaar ek spare gene hai jiski humein shayad bahut zaroorat pade jab koi nayi bimaari ya sookha aaye.\n","persona_id":"nova"},"xp_reward":0},{"order_index":6,"turn_type":"tutor_message","content":{"text":"Concrete banaate hain.\n\n**Agriculture** mein, hum *abhi bhi* **traditional crop varieties** pe depend karte hain — unke genes mein woh resilience hota hai jo modern hybrids mein aksar nahi. Aur **fisheries** poori tarah **aquatic biodiversity** ko zinda rakhne pe depend karti hain.\n\nVariety kho do, aur fasal kho do — zameen pe aur samundar mein.\n","persona_id":"nova"},"xp_reward":0},{"order_index":7,"turn_type":"html_animation","content":{"title":"VARIETY KYUN INSURANCE HAI","caption":"Jab ek crop variety fail hoti hai, doosri bach jaati hai — yahi genetic diversity humein khareed ke deti hai.","html":"<div style=\"background:#f8fafc;padding:18px 12px;border-radius:12px;text-align:center;\">\n  <style>\n    @keyframes geoFailSeed { 0%,30%{fill:#16a34a} 60%,100%{fill:#9ca3af} }\n    .geo-fail { animation: geoFailSeed 4s ease-in-out infinite alternate; }\n  </style>\n  <svg viewBox=\"0 0 300 96\" style=\"max-width:320px;width:100%\" font-family=\"sans-serif\">\n    <circle cx=\"50\" cy=\"38\" r=\"16\" class=\"geo-fail\" stroke=\"#0f172a\" stroke-width=\"1\"/>\n    <circle cx=\"110\" cy=\"38\" r=\"16\" fill=\"#16a34a\" stroke=\"#0f172a\" stroke-width=\"1\"/>\n    <circle cx=\"170\" cy=\"38\" r=\"16\" fill=\"#16a34a\" stroke=\"#0f172a\" stroke-width=\"1\"/>\n    <circle cx=\"230\" cy=\"38\" r=\"16\" fill=\"#16a34a\" stroke=\"#0f172a\" stroke-width=\"1\"/>\n    <text x=\"150\" y=\"80\" text-anchor=\"middle\" font-size=\"8\" fill=\"#475569\">one variety fails — the others still feed us</text>\n  </svg>\n</div>\n"},"xp_reward":0},{"order_index":8,"turn_type":"tutor_message","content":{"text":"Sab jod ke. *Agar biodiversity chali jaaye toh kya tootega?*\n\nTeen cheezein ek saath fail hoti hain: hamari hawa, paani, aur mitti ke cleaners; woh gene bank jis pe hamare khet chupchaap depend karte hain; aur samundar ki machhliyan.\n\nToh conservation sentimental nahi hai. Yeh **self-preservation** hai — humare liye.\n","persona_id":"nova"},"xp_reward":0},{"order_index":9,"turn_type":"mcq","content":{"question":"Insaano ke liye biodiversity bachana kyun maayne rakhta hai — sabse achha kya pakadta hai?","options":[{"id":"a","text":"Mukhya roop se taaki humare paas dekhne aur ghoomne ke liye khoobsurat jaanwar hon.","is_correct":false,"rationale":"Khoobsurati aur tourism achhe hain, par chapter ki wajahein kahin zyaada basic hain — survival, scenery nahi."},{"id":"b","text":"Yeh hamare life-support systems (hawa, paani, mitti) aur woh genetic diversity bachata hai jis pe hamari kheti aur fisheries depend karti hain.","is_correct":true,"rationale":"Bilkul. Conservation ecological *aur* genetic diversity dono bachata hai — woh systems aur gene banks jin pe hum jeete hain."},{"id":"c","text":"Kyunki kaanoon kehta hai, aur koi gehri wajah nahi.","is_correct":false,"rationale":"Kaanoon in *gehri wajahon* ki wajah se hi maujood hai — life-support systems aur genetic diversity."},{"id":"d","text":"Sirf kuch mashhoor jaanwaron jaise tiger ko bachane ke liye.","is_correct":false,"rationale":"Aaj ki conservation poori biodiversity pe focus karti hai, sirf kuch species pe nahi — aur wajahein kisi ek jaanwar se kahin aage jaati hain."}],"xp":10},"xp_reward":10},{"order_index":10,"turn_type":"tap_to_match","content":{"prompt":"Conservation kya bachata hai, use uss se match karo jo humare liye maayne rakhti hai.","left":[{"id":"l1","label":"Ecological diversity"},{"id":"l2","label":"Genetic diversity"},{"id":"l3","label":"Traditional crop varieties"},{"id":"l4","label":"Aquatic biodiversity"}],"right":[{"id":"r1","label":"Hamari hawa, paani, aur mitti ko chalti rakhti hai"},{"id":"r2","label":"Behtar species breed karne ke liye backup genes"},{"id":"r3","label":"Jis pe hamari agriculture abhi bhi tiki hai"},{"id":"r4","label":"Jis pe hamari fisheries depend karti hain"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]},"xp_reward":10},{"order_index":11,"turn_type":"exercise","content":{"instruction":"Aaj khaaya koi ek khaana chuno — chawal, machhli, ek phal, dal.\n\nPaper pe use trace karo: kaunse jeev aur kaunsi *variety* ya *species* ne use mumkin banaya? Agar uski biodiversity gayab ho jaaye toh us khaane ka kya hoga? Neeche khaana aur apna ek-line jawaab type karo.\n","tool":"pencil","placeholder":"Mera ___ ___ pe depend karta hai; uske bina..."},"xp_reward":15},{"order_index":12,"turn_type":"fill_in_the_blank","content":{"prompt":"Do wajahein yaad kar lo.","template":"Conservation hamare life-support systems (hawa, paani, mitti) aur woh {{blank-1}} diversity bachata hai jo behtar crops breed karne ke liye chahiye; hamari {{blank-2}} aquatic biodiversity pe depend karti hain.\n","answers":[{"id":"blank-1","accepted":["genetic","Genetic"]},{"id":"blank-2","accepted":["fisheries","Fisheries","fishery"]}]},"xp_reward":10},{"order_index":13,"turn_type":"reflection","content":{"prompt":"Conservation \"self-preservation hai, daan nahi.\" Kya ise is tarah dekhna tumhe ise zyaada seriously lene pe majboor karta hai — ya kuch kho jaata hai jab hum nature ko sirf uske liye value karte hain jo woh *humare liye* karta hai?\n\nKoi sahi jawaab nahi.\n","placeholder":"Self-preservation ki tarah dekhne se, main..."},"xp_reward":5},{"order_index":14,"turn_type":"checkpoint","content":{"title":"Tum thos wajahein de sakte ho ki biodiversity kyun bachane laayak hai.","summary":"Conservation hamare life-support systems — hawa, paani, mitti — aur woh genetic diversity bachata hai jis pe hamare khet aur fisheries chupchaap depend karte hain. Yeh jaanwaron ke liye daan nahi; yeh humare liye suraksha hai.\n\nToh hum jaante hain *kyun*. Ab mushkil sawaal: ek poora desh apne forests aur wildlife ko *kaise* bachata hai? Yeh shuru hua, 1972 mein, ek hi taaqatwar kaanoon se. Yahin se agla course shuru hota hai.\n","xp":0},"xp_reward":0}]}}$lj$::jsonb, 3, 11, 100, 'ai_chat', true)
