  -- communities-and-conservation/when-villages-defend-the-forest
  VALUES ((SELECT id FROM courses WHERE slug = 'communities-and-conservation'), 'when-villages-defend-the-forest', $lj${"en":{"title":"When Villages Defend the Forest","subtitle":"Sometimes the forest's best guard is the village next door"},"hinglish":{"title":"Jab Gaon Forest ki Raksha Karte Hain","subtitle":"Kabhi-kabhi forest ka sabse achha rakhwaala paas waala gaon hota hai","turns":[{"order_index":1,"turn_type":"tutor_message","content":{"text":"Jab ek mining company Rajasthan ke Sariska forest ke liye aayi, toh use police ne wapas nahi bheja.\n\nUse **gaon waalon** ne wapas bheja — sirf ek kaanoon aur apni himmat ke saath. Aur woh jeet gaye.\n","persona_id":"nova"},"xp_reward":0},{"order_index":2,"turn_type":"tutor_message","content":{"text":"Conservation India mein koi nayi government idea nahi hai. Forests hamesha se traditional communities ka **ghar** rahe hain.\n\nAur poore desh mein, woh communities apne forests ko bachane ke liye lad rahi hain — kyunki woh samajhti hain ki unki apni *long-term livelihood* ispe depend karti hai.\n","persona_id":"nova"},"xp_reward":0},{"order_index":3,"turn_type":"tutor_message","content":{"text":"**Sariska Tiger Reserve, Rajasthan** ko lo. Gaon waalon ne **Wildlife Protection Act** ka hawaala dekar **mining** ko bhagaaya — pichhle course ke kaanoon ko apna hathiyaar bana ke.\n\nKai jagahon pe, gaon waale habitats khud bachaate hain — kabhi-kabhi government ke involvement ko poori tarah thukraate hue.\n","persona_id":"nova"},"xp_reward":0},{"order_index":4,"turn_type":"tutor_message","content":{"text":"Phir hai **Bhairodev Dakav 'Sonchuri'.**\n\nAlwar district, Rajasthan mein, **paanch gaon** ke logon ne **1,200 hectares** forest ko apna *khud ka* sanctuary ghoshit kiya — apne *khud ke* niyamon ke saath: koi shikaar nahi, koi bahari encroachment nahi. Ek janta ka protected area, poori tarah janta dwara chalaya.\n","persona_id":"nova"},"xp_reward":0},{"order_index":5,"turn_type":"media","content":{"kind":"image","url":"https://dfdocnhhxrnvblbwwium.supabase.co/storage/v1/object/public/lesson-images/b-class-10-geography-ch02-forest-and-wildlife-resources/c3l1-chipko.png","caption":"Chipko andolan: gaonwaale pedon ko gale lagaakar unhe katne se rokte hue.","aspect_ratio":1.7778},"xp_reward":0},{"order_index":6,"turn_type":"svg_graphic","content":{"title":"FOREST KE PADOSI","caption":"India bhar mein, forest ke paas rehne waali communities uski rakhwaale ban gayi.","svg":"<svg viewBox=\"0 0 360 180\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <line x1=\"180\" y1=\"92\" x2=\"80\" y2=\"40\" stroke=\"#cbd5e1\" stroke-width=\"1.5\"/>\n  <line x1=\"180\" y1=\"92\" x2=\"290\" y2=\"40\" stroke=\"#cbd5e1\" stroke-width=\"1.5\"/>\n  <line x1=\"180\" y1=\"92\" x2=\"180\" y2=\"150\" stroke=\"#cbd5e1\" stroke-width=\"1.5\"/>\n  <circle cx=\"155\" cy=\"92\" r=\"16\" fill=\"#16a34a\"/><rect x=\"152\" y=\"100\" width=\"6\" height=\"12\" fill=\"#92400e\"/>\n  <circle cx=\"185\" cy=\"86\" r=\"20\" fill=\"#15803d\"/><rect x=\"182\" y=\"98\" width=\"7\" height=\"14\" fill=\"#92400e\"/>\n  <circle cx=\"210\" cy=\"94\" r=\"15\" fill=\"#16a34a\"/><rect x=\"207\" y=\"101\" width=\"6\" height=\"11\" fill=\"#92400e\"/>\n  <rect x=\"14\" y=\"22\" width=\"132\" height=\"34\" rx=\"5\" fill=\"#fef9c3\" stroke=\"#0f172a\" stroke-width=\"1\"/>\n  <text x=\"80\" y=\"38\" text-anchor=\"middle\" font-size=\"9\" font-weight=\"bold\" fill=\"#854d0e\">Sariska</text>\n  <text x=\"80\" y=\"50\" text-anchor=\"middle\" font-size=\"8\" fill=\"#475569\">villagers fought mining</text>\n  <rect x=\"220\" y=\"22\" width=\"132\" height=\"34\" rx=\"5\" fill=\"#fef9c3\" stroke=\"#0f172a\" stroke-width=\"1\"/>\n  <text x=\"286\" y=\"38\" text-anchor=\"middle\" font-size=\"9\" font-weight=\"bold\" fill=\"#854d0e\">Bhairodev Sonchuri</text>\n  <text x=\"286\" y=\"50\" text-anchor=\"middle\" font-size=\"8\" fill=\"#475569\">5 villages, 1,200 hectares</text>\n  <rect x=\"114\" y=\"154\" width=\"132\" height=\"22\" rx=\"5\" fill=\"#fef9c3\" stroke=\"#0f172a\" stroke-width=\"1\"/>\n  <text x=\"180\" y=\"168\" text-anchor=\"middle\" font-size=\"9\" font-weight=\"bold\" fill=\"#854d0e\">Chipko — hugged the trees</text>\n</svg>\n"},"xp_reward":0},{"order_index":7,"turn_type":"tutor_message","content":{"text":"Aur sabse mashhoor — Himalaya mein **Chipko movement**.\n\nGaon waale literally *pedon se chipak gaye* taaki woh kate na (*chipko* matlab \"gale lagana\" ya \"chipakna\"). Isne sirf kai ilaaqon mein deforestation nahi roki — isne *saabit* kiya ki **indigenous species ke saath community afforestation** bade paimaane pe safal ho sakti hai.\n","persona_id":"nova"},"xp_reward":0},{"order_index":8,"turn_type":"html_animation","content":{"title":"CHIPKO — PED SE CHIPKO","caption":"Jab gaon waalon ne pedon ke charon taraf baahein lapeti, toh kulhaadi ko rukna pada.","html":"<div style=\"background:#f8fafc;padding:18px 12px;border-radius:12px;text-align:center;\">\n  <style>\n    @keyframes geoAxe { 0%,40%{transform:translateX(0);opacity:1} 60%,100%{transform:translateX(-26px);opacity:0.25} }\n    @keyframes geoArm { 0%,20%{opacity:0} 45%,100%{opacity:1} }\n    .geo-axe{animation:geoAxe 4s ease-in-out infinite alternate}\n    .geo-arm{animation:geoArm 4s infinite alternate}\n  </style>\n  <svg viewBox=\"0 0 300 130\" style=\"max-width:300px;width:100%\" font-family=\"sans-serif\">\n    <rect x=\"146\" y=\"40\" width=\"10\" height=\"70\" fill=\"#92400e\"/>\n    <circle cx=\"151\" cy=\"36\" r=\"22\" fill=\"#16a34a\"/>\n    <path class=\"geo-arm\" d=\"M120,80 Q151,66 182,80\" stroke=\"#0f172a\" stroke-width=\"4\" fill=\"none\"/>\n    <circle class=\"geo-arm\" cx=\"116\" cy=\"82\" r=\"7\" fill=\"#fcd34d\" stroke=\"#0f172a\" stroke-width=\"1\"/>\n    <circle class=\"geo-arm\" cx=\"186\" cy=\"82\" r=\"7\" fill=\"#fcd34d\" stroke=\"#0f172a\" stroke-width=\"1\"/>\n    <g class=\"geo-axe\"><rect x=\"232\" y=\"60\" width=\"28\" height=\"5\" fill=\"#475569\"/><polygon points=\"232,54 232,72 220,63\" fill=\"#94a3b8\"/></g>\n    <text x=\"150\" y=\"124\" text-anchor=\"middle\" font-size=\"8\" fill=\"#166534\">arms around the trunk — the axe retreats</text>\n  </svg>\n</div>\n"},"xp_reward":0},{"order_index":9,"turn_type":"tutor_message","content":{"text":"Har kahani mein pattern gaur karo.\n\nWoh log jo forest ke *paas rehte* the — koi door ka niyam nahi — usne use bachaya. Forest ke sabse achhe rakhwaale uske **padosi** nikalte hain.\n","persona_id":"nova"},"xp_reward":0},{"order_index":10,"turn_type":"mcq","content":{"question":"Sariska ke gaon waalon ne tiger reserve ke andar mining kaise roki?","options":[{"id":"a","text":"Mining company ko jaane ke liye paisa dekar.","is_correct":false,"rationale":"Koi payment nahi hui. Unhone legal raasta istemal kiya, paisa nahi."},{"id":"b","text":"Mining ko challenge karne ke liye Wildlife Protection Act ka hawaala dekar.","is_correct":true,"rationale":"Bilkul — gaon waalon ne 1972 ke kaanoon ko reserve bachane ka apna hathiyaar bana liya."},{"id":"c","text":"Central government ke army bhejne ka wait karke.","is_correct":false,"rationale":"Kahani ka point yahi hai ki *community* ne action liya, koi door ka authority nahi."},{"id":"d","text":"Pehle khud forest saaf karke.","is_correct":false,"rationale":"Yeh conservation ka ulta hai — woh forest bacha rahe the, saaf nahi kar rahe the."}],"xp":10},"xp_reward":10},{"order_index":11,"turn_type":"tap_to_match","content":{"prompt":"Har community action ko us se match karo jo woh tha.","left":[{"id":"l1","label":"Sariska, Rajasthan"},{"id":"l2","label":"Bhairodev Dakav 'Sonchuri'"},{"id":"l3","label":"Chipko movement"}],"right":[{"id":"r1","label":"Gaon waalon ne Wildlife Protection Act se mining ladi"},{"id":"r2","label":"Paanch gaon ne 1,200 hectares ko apna sanctuary ghoshit kiya"},{"id":"r3","label":"Logon ne Himalaya mein deforestation rokne ko pedon se chipke rahe"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"]]},"xp_reward":10},{"order_index":12,"turn_type":"exercise","content":{"instruction":"Socho ek tareeka jisse *tumhare jaane-pehchaane log* — ek gaon, parivaar, mandir, ya school — apne paas ek ped, jaanwar, talaab, ya hariyaali ke tukde ko bachaate hain.\n\nPaper pe do line mein likho. Phir neeche type karo ki kya bachaaya jaata hai aur kaun bachaata hai.\n","tool":"pencil","placeholder":"Mere paas, ___ ___ ko bachaate hain."},"xp_reward":15},{"order_index":13,"turn_type":"fill_in_the_blank","content":{"prompt":"Do community actions yaad kar lo.","template":"Sariska mein, gaon waalon ne {{blank-1}} Act ka hawaala dekar mining roki; Chipko movement mein, log pedon se {{blank-2}} taaki unhe bacha sakein.\n","answers":[{"id":"blank-1","accepted":["Wildlife Protection","wildlife protection","Wildlife (Protection)"]},{"id":"blank-2","accepted":["chipke","chipak gaye","lipat gaye","chimat gaye"]}]},"xp_reward":10},{"order_index":14,"turn_type":"reflection","content":{"prompt":"Sariska aur Chipko ke gaon waalon ne aise forests bachaye jo kaanoon ke hisaab se unke \"apne\" nahi the. Tumhe kya lagta hai unhe kis cheez ne itni saxti se ladne pe majboor kiya, ek aisi cheez ke liye jo kaagaz pe unki nahi thi?\n\nKoi sahi jawaab nahi.\n","placeholder":"Mujhe lagta hai woh isliye lade kyunki..."},"xp_reward":5},{"order_index":15,"turn_type":"checkpoint","content":{"title":"Tum dikha sakte ho ki communities khud India ke forests kaise bachaati hain.","summary":"Sariska ki mining ke khilaaf ladai se, Bhairodev mein ek janta ke sanctuary tak, ped-galagad Chipko movement tak — baar-baar, forest ke padosi uske rakhwaale ban gaye.\n\nPar forest bachana sirf aadha hissa hai. Doosra aadha hai usse *jeena* bina use barbaad kiye. Communities nature ke saath partnership mein kheti aur harvest kaise karti hain? Yahi agli lesson hai.\n","xp":0},"xp_reward":0}]}}$lj$::jsonb, 1, 11, 100, 'ai_chat', true)
