  -- protecting-forests-and-wildlife/project-tiger
  VALUES ((SELECT id FROM courses WHERE slug = 'protecting-forests-and-wildlife'), 'project-tiger', $lj${"en":{"title":"Project Tiger","subtitle":"Why saving one big cat meant saving an entire forest"},"hinglish":{"title":"Project Tiger","subtitle":"Ek badi billi ko bachana ek poore forest ko bachana kyun bana","turns":[{"order_index":1,"turn_type":"tutor_message","content":{"text":"Lagbhag 1900 ke aas-paas, India mein lagbhag **55,000 tigers** the.\n\n1973 tak, jab kisi ne aakhir ginti ki, sirf **1,827** bache the.\n\nYeh giraavat nahi. Yeh collapse hai. Hua kya — aur tiger bachana poore forest ko bachana kaise ban gaya?\n","persona_id":"nova"},"xp_reward":0},{"order_index":2,"turn_type":"tutor_message","content":{"text":"Tiger faunal web ki ek **key species** hai — bilkul top pe ek shikaari.\n\nJab authorities ne 1973 mein jaayza liya, crash ka paimaana saaf tha: lagbhag **55,000** se ghat ke **1,827**.\n","persona_id":"nova"},"xp_reward":0},{"order_index":3,"turn_type":"media","content":{"kind":"image","url":"https://dfdocnhhxrnvblbwwium.supabase.co/storage/v1/object/public/lesson-images/b-class-10-geography-ch02-forest-and-wildlife-resources/c2l2-bengal-tiger.png","caption":"Bengal tiger — Project Tiger ka, aur India ke poore conservation ka, flagship.","aspect_ratio":1.7778},"xp_reward":0},{"order_index":4,"turn_type":"svg_graphic","content":{"title":"TIGER KA COLLAPSE","caption":"1900 mein lagbhag 55,000 tigers se ghat ke 1973 tak sirf 1,827.","svg":"<svg viewBox=\"0 0 360 180\" xmlns=\"http://www.w3.org/2000/svg\" font-family=\"sans-serif\">\n  <line x1=\"40\" y1=\"150\" x2=\"330\" y2=\"150\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <rect x=\"70\" y=\"32\" width=\"70\" height=\"118\" fill=\"#f59e0b\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"105\" y=\"26\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"bold\" fill=\"#92400e\">55,000</text>\n  <text x=\"105\" y=\"165\" text-anchor=\"middle\" font-size=\"9\" fill=\"#475569\">~1900</text>\n  <rect x=\"230\" y=\"142\" width=\"70\" height=\"8\" fill=\"#f59e0b\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n  <text x=\"265\" y=\"134\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"bold\" fill=\"#b91c1c\">1,827</text>\n  <text x=\"265\" y=\"165\" text-anchor=\"middle\" font-size=\"9\" fill=\"#475569\">1973</text>\n  <path d=\"M150,40 Q200,30 224,132\" stroke=\"#b91c1c\" stroke-width=\"2\" fill=\"none\" stroke-dasharray=\"5 3\"/>\n  <polygon points=\"224,132 219,120 230,124\" fill=\"#b91c1c\"/>\n</svg>\n"},"xp_reward":0},{"order_index":5,"turn_type":"tutor_message","content":{"text":"Crash kisne laaya? Chaar forces, ek saath:\n\n- vyaapaar ke liye **poaching** (avaidh shikaar)\n- forests katne se **shrinking habitat**\n- **prey ki kami** — kam hiran aur suar shikaar ke liye\n- tiger ke ilaaqe mein ghuste **badhti human population**\n","persona_id":"nova"},"xp_reward":0},{"order_index":6,"turn_type":"tutor_message","content":{"text":"Sabse khatarnaak khinchaav tha *trade*.\n\nTiger ki **khaal**, aur **haddiyaan** jo traditional medicines mein use hoti thi — khaaskar kai Asian deshon mein — tiger ko zinda se zyaada mara hua keemti bana deti thi. Aur kyunki India aur Nepal duniya ke bache tigers ka lagbhag **do-tihaai** rakhte hain, woh poachers aur avaidh traders ke prime targets ban gaye.\n","persona_id":"nova"},"xp_reward":0},{"order_index":7,"turn_type":"tutor_message","content":{"text":"Toh **1973** mein, India ne **Project Tiger** launch kiya — duniya ke sabse zyaada publicised wildlife campaigns mein se ek.\n\nPar iske dil mein ek chalaak idea hai.\n","persona_id":"nova"},"xp_reward":0},{"order_index":8,"turn_type":"tutor_message","content":{"text":"Ek tiger ko ek vishaal, swasth forest chahiye — prey, paani, aur cover se bhara. *Use* bachao, aur tum apne aap usme rehne waali *har* cheez ko bacha lete ho.\n\nTiger ek **umbrella** hai: badi billi pe protection failao, aur uski chhaaya hiran, parindon, keedon, pedon — poore web ko dhakti hai.\n","persona_id":"nova"},"xp_reward":0},{"order_index":9,"turn_type":"html_animation","content":{"title":"TIGER KA UMBRELLA","caption":"Tiger ke forest ko bachao, aur uske neeche ki har species bhi surakshit ho jaati hai.","html":"<div style=\"background:#f8fafc;padding:18px 12px;border-radius:12px;text-align:center;\">\n  <style>\n    @keyframes geoOpen { 0%,10%{transform:scale(0.2);opacity:0} 55%,100%{transform:scale(1);opacity:1} }\n    @keyframes geoUnder { 0%,45%{opacity:0} 70%,100%{opacity:1} }\n    .geo-canopy { transform-origin:center bottom; animation: geoOpen 4.5s ease-out infinite alternate; }\n    .geo-under { animation: geoUnder 4.5s infinite alternate; }\n  </style>\n  <svg viewBox=\"0 0 300 130\" style=\"max-width:320px;width:100%\" font-family=\"sans-serif\">\n    <path class=\"geo-canopy\" d=\"M40,70 A110,70 0 0 1 260,70 Z\" fill=\"#f59e0b\" stroke=\"#0f172a\" stroke-width=\"1.5\"/>\n    <text x=\"150\" y=\"58\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#7c2d12\" class=\"geo-canopy\">TIGER</text>\n    <g class=\"geo-under\" fill=\"#16a34a\">\n      <circle cx=\"90\" cy=\"100\" r=\"11\"/><circle cx=\"130\" cy=\"104\" r=\"9\"/>\n      <circle cx=\"170\" cy=\"104\" r=\"9\"/><circle cx=\"210\" cy=\"100\" r=\"11\"/>\n    </g>\n    <text x=\"150\" y=\"126\" text-anchor=\"middle\" font-size=\"8\" fill=\"#475569\" class=\"geo-under\">deer, birds, insects, trees — all sheltered</text>\n  </svg>\n</div>\n"},"xp_reward":0},{"order_index":10,"turn_type":"tutor_message","content":{"text":"Project Tiger India bhar mein mashhoor reserves mein faila: **Corbett** Uttarakhand mein, **Sunderbans** West Bengal mein, **Bandhavgarh** Madhya Pradesh mein, **Sariska** Rajasthan mein, **Manas** Assam mein, aur **Periyar** Kerala mein.\n\nAur conservation badi hoti gayi. Ab yeh *poori biodiversity* ki rakhwaali karti hai, sirf kuch stars ki nahi — yahan tak ki **insects** ki. Wildlife Act ke notifications (1980, 1986) ne butterflies, moths, beetles, ek dragonfly tak jode; **1991** mein, pehli baar plants protected list mein aaye.\n","persona_id":"nova"},"xp_reward":0},{"order_index":11,"turn_type":"mcq","content":{"question":"Tiger ko bachane ko poore forest ko bachana kyun kaha jaata hai?","options":[{"id":"a","text":"Kyunki tigers ghoomte hue naye ped lagaate hain.","is_correct":false,"rationale":"Tigers ped nahi lagaate. Wajah *habitat* ke baare mein hai, baagwaani ke nahi."},{"id":"b","text":"Ek tiger ko ek bada, swasth forest chahiye jo prey se bhara ho — toh uske ghar ko bachana usme rehne waali har species ko bachata hai.","is_correct":true,"rationale":"Bilkul. Tiger ek 'umbrella' species hai: uske habitat ko bachao aur uske neeche poora web surakshit ho jaata hai."},{"id":"c","text":"Kyunki kaanoon sirf un forests ko bachata hai jisme tigers hain.","is_correct":false,"rationale":"Protection sirf tiger forests tak seemit nahi. Point ecological hai — tiger ki zaroortein baaki sabki dhakti hain."},{"id":"d","text":"Kyunki tigers un jaanwaron ko khaate hain jo forests ko nuksaan pahunchaate hain.","is_correct":false,"rationale":"Tempting, par chapter ka logic habitat ke size aur health ke baare mein hai, pest control ka nahi."}],"xp":10},"xp_reward":10},{"order_index":12,"turn_type":"tap_to_match","content":{"prompt":"Har tiger reserve ko uske rajya se match karo.","left":[{"id":"l1","label":"Corbett"},{"id":"l2","label":"Sunderbans"},{"id":"l3","label":"Bandhavgarh"},{"id":"l4","label":"Periyar"}],"right":[{"id":"r1","label":"Uttarakhand"},{"id":"r2","label":"West Bengal"},{"id":"r3","label":"Madhya Pradesh"},{"id":"r4","label":"Kerala"}],"pairs":[["l1","r1"],["l2","r2"],["l3","r3"],["l4","r4"]]},"xp_reward":10},{"order_index":13,"turn_type":"exercise","content":{"instruction":"Is lesson se koi ek tiger reserve ya national park chuno (ya koi jise tum jaante ho).\n\nMap pe ya paper pe use locate karo aur uska rajya likho. Phir is lesson se ek threat likho jisse Project Tiger ko ladna pada. Neeche reserve aur threat type karo.\n","tool":"pencil","placeholder":"___ ___ mein hai; tigers ko ek threat hai ___."},"xp_reward":15},{"order_index":14,"turn_type":"fill_in_the_blank","content":{"prompt":"Key facts yaad kar lo.","template":"Project Tiger {{blank-1}} mein launch hua, aur India aur Nepal milke duniya ke bache tigers ka lagbhag {{blank-2}} rakhte hain.\n","answers":[{"id":"blank-1","accepted":["1973"]},{"id":"blank-2","accepted":["two-thirds","two thirds","2/3","do-tihaai","do tihaai"]}]},"xp_reward":10},{"order_index":15,"turn_type":"reflection","content":{"prompt":"Ek hi mashhoor jaanwar ne ek poore forest bhar ke jeevan ko protection ke neeche kheench liya. Kya yeh sahi hai ki unglamorous species sirf isliye bach gayi kyunki woh ek tiger ke paas rehti thi? Yeh humare protect karne ke chunaav ke baare mein kya kehta hai?\n\nKoi sahi jawaab nahi.\n","placeholder":"Mujhe lagta hai ek flagship species chunna..."},"xp_reward":5},{"order_index":16,"turn_type":"checkpoint","content":{"title":"Tum Project Tiger ki kahani — aur uske peeche umbrella idea — bata sakte ho.","summary":"55,000 se 1,827, tiger lagbhag gayab ho gaya — poaching, khoye habitat, khoye prey, aur human pressure se. Project Tiger (1973) ne palatwaar kiya — aur tiger ke forest ko bachakar, usne poore web ko dhaka, samay ke saath insects aur plants tak failta gaya.\n\nPar forests khud alag-alag tareekon se sorted aur guarded hote hain. Kuch India ke sabse strictly protected hain; kuch local communities ke bharose chhode. India ke forests classify kaise hote hain? Yahi agli lesson hai.\n","xp":0},"xp_reward":0}]}}$lj$::jsonb, 2, 12, 100, 'ai_chat', true)
